import { mls } from "../../src/index";
import * as serviceWorkerIndex from "./stor.serviceWorkerIndex.js";

const MLSSERVICEWORKERVERSION = "[MLSSERVICEWORKERVERSION]";

/**
 * register the mlsServiceWork if not registered yet
 */
export const installIfNeeded = async (): Promise<ServiceWorkerRegistration | null> => {
  if (!('serviceWorker' in navigator)) return null;

  const need = await serviceWorkerNeedUpdate();
  let url = location.host === "multilevelstudio.com"
    ? "https://multilevelstudio.com/mlsServiceWorker.js"
    : "https://on.collab.codes/mlsServiceWorker.js";
  if (location.host === "collab.codes") url = "https://collab.codes/mlsServiceWorker.js"; // old
  if (location.host === "test.collab.codes") url = "https://test.collab.codes/mlsServiceWorker.js";
  if (location.host !== "multilevelstudio.com" && location.host !== "collab.codes" && !location.host.endsWith(".collab.codes")) {
    // Runtime VM: localhost, *.collabcodes.com and client custom domains.
    // Service workers must be same-origin, and the 102034 cbe module serves
    // /mlsServiceWorker.js on the app origin.
    url = `${location.origin}/mlsServiceWorker.js`;
  }

  let reg = await navigator.serviceWorker.getRegistration();
  if (!reg || need) {
    // Force fresh fetch
    reg = await navigator.serviceWorker.register(url, { updateViaCache: "none" });
    await reg.update();
    // Allow cache afterwards (optional)
    reg = await navigator.serviceWorker.register(url, { updateViaCache: "all" });
  }

  // Wait until the SW takes control
  await navigator.serviceWorker.ready;
  return reg!;
};

export const serviceWorkerNeedUpdate = async (): Promise<boolean> => {
  if (!("serviceWorker" in navigator)) return false;

  const registrations = await navigator.serviceWorker.getRegistrations();

  // First execution: no Service Worker installed yet
  if (registrations.length === 0) {
    return true;
  }

  return ((await getStatistics())?.versionSW !== MLSSERVICEWORKERVERSION);
}

/**
 * Adds a JS resource to the cache.
 *
 * @param path The path of the resource.
 * @param version The version of the resource.
 * @param js The JS resource as a string.
 *
 * @returns A promise that resolves when the operation is complete, a path to use in fetch.
 * @throws An error if the operation fails.
 */
export const addIfNeed = async (args: {project: number, folder: string | null, shortName: string, version: string, content: string | Blob | null, extension: string, contentType?: string}): Promise<string> => {
  const path = getPathSuffix(args.project, args.folder, args.shortName, args.extension);
  const contentType: string = args.content instanceof Blob ? args.content.type || 'application/octet-stream' : args.contentType || 'application/javascript';
  if (mls.istrace) console.log(`addIfNeed: ${path}, version: ${args.version}`);
  return sendToServiceWorkerAndGetReturn({
    action: 'add',
    path,
    version: args.version,
    content: args.content,
    contentType,
  });
};

export const addsIfNeed = async (args: {project: number, folder: string[], shortName: string[], version: string[], content: string[], extension: string[], contentType: string[]}): Promise<string> => {
  if (args.folder.length !== args.shortName.length || args.folder.length !== args.version.length || args.folder.length !== args.content.length || args.folder.length !== args.extension.length || args.folder.length !== args.contentType.length) throw new Error('addsIfNeed: invalid parameters');
  const path: string[] = args.folder.map((folder, index) => getPathSuffix(args.project, folder, args.shortName[index], args.extension[index]));
  if (mls.istrace) console.log(`addIfNeed: ${path}, version: ${args.version}, content-length: ${args.content.length}`);
  return sendToServiceWorkerAndGetReturn({
    action: 'adds',
    path,
    version: args.version,
    content: args.content,
    contentType: args.contentType,
  });
};


/**
 * add a L2 resource to the cache
 * @returns A promise that resolves when the operation is complete, a path to use in fetch.
 * @throws An error if the operation fails.
 */
export const AddMfileIfNeed = async (modelTS: mls.editor.IModelTS): Promise<string> => {
  const { project, shortName, folder } = modelTS.storFile;
  const version = modelTS.compilerResults?.cacheVersion;
  const js = modelTS.compilerResults?.prodJS || "";
  const extension = ".js";
  if (!version) return "";
  const url = await getURL(project, folder, shortName, extension, version);
  if (url) return url;
  return addIfNeed({ project, folder, shortName, version, content: js, extension });
}

/**
 * get file from local cache , without no send to ServiceWorker
 */
export const getFileFromCache = async (project: number, folder: string | null, shortName: string, extension: string, version: string): Promise<string | null> => {
  const url = getUrlLocalWithVersion(project, folder, shortName, extension, version);
  const cachedResponse = await caches.match(url);
  if (!cachedResponse) return null;
  return (await cachedResponse.text()) || null;
}


/**
 * get url to use in import statement, to find browser local cache only
 * if not in the cache, return null
 */
export const getURL = async (project: number, folder: string | null, shortName: string, extension: string, version: string): Promise<string | null> => {
  const path = getPathSuffix(project, folder, shortName, extension);
  const message: serviceWorkerIndex.ServiceWorkerMessage = {
    action: 'getURL',
    path,
    version
  };
  return sendToServiceWorkerAndGetReturn(message);
}

export interface IServiceWorkerSts {
  versionSW: string;
  isTrace: boolean;
  totalRequests: number;
  totalHits: number;
  totalNotFound: number;
  totalInserts: number;
}

/**
 * get statistics for nerd
 */
export const getStatistics = async (): Promise<IServiceWorkerSts | null> => {
  try {
    const result: string = await sendToServiceWorkerAndGetReturn({ action: 'sts' });
    const sts: IServiceWorkerSts = JSON.parse(result);
    return sts;
  } catch (error) {
    console.error(`Error parsing service worker statistics: ${error}`);
    return null;
  }
}

 /**
 * search in local cache (browser cache)
 * @param fileInfo information of file
 * @returns content or null (not in browser cache)
 */
export const getContent = async (fileInfo: mls.stor.IFileInfo): Promise<string | Blob | null> => {
  const path = await getURL(fileInfo.project, fileInfo.folder, fileInfo.shortName, fileInfo.extension, fileInfo.versionRef);
  if (!path) return null;
  return getFetch(path);
}

/**
 * stor content in local cache (browser cache) for future use
 * @param fileInfo information of file
 * @param content or null (erase)
 */
export const setContent = async (fileInfo: mls.stor.IFileInfo, content: string | Blob | null): Promise<string> => {
  const path = getPathSuffix(fileInfo.project, fileInfo.folder, fileInfo.shortName, fileInfo.extension);
  const contentType: string = content instanceof Blob ? content.type || 'application/octet-stream' : 'text/plain';
  return sendToServiceWorkerAndGetReturn({
    action: 'add',
    path,
    version: fileInfo.versionRef,
    content,
    contentType,
  });
}

/**
 * Fetch a resource and return its content as a string, Blob or null.
 * @param {string} url The URL of the resource to fetch.
 * @return {Promise<string | Blob | null>} The content of the resource.
 */
const getFetch = async (url: string): Promise<string | Blob | null> => {
  try {
    const response = await fetch(url);
    if (!response.ok) return null;
    const contentType = response.headers.get("content-type");

    if (contentType &&
      (contentType.startsWith("text/") ||
      contentType.includes("application/json") ||
      contentType.includes("application/javascript") ||
      contentType.includes("application/typescript") ||
      contentType.includes("application/xml"))) {
      return await response.text();
    } else {
      return await response.blob();
    }
    // console.error('Unknown content type on cache:', contentType);
  } catch (error) {
    console.error(`There was an error with the fetch operation: ${error}`);
  }
  return null;
};


/**
 * Sends a message to the service worker.
 *
 * @param message The message to send.
 *
 * @returns A promise that resolves when the operation is complete.
 * @throws An error if the operation fails.
 */
const sendToServiceWorker = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<void> => {
  if (!('serviceWorker' in navigator)) {
    throw new Error('Service workers are not supported in this browser.');
  }

  // navigator.serviceWorker.ready.then(registration => {
  //   registration.active?.postMessage(message);
  // }).catch((error: Error | string) => {
  //   if (error instanceof Error) throw new Error(`Failed to send message to service worker: ${error.message}`);
  //   throw new Error(`Failed to send message to service worker: ${error}`);
  // });


  try {
    const registration = await navigator.serviceWorker.ready;
    if (!registration.active) {
      console.warn('No active service worker to receive the message.');
      return;
    }
    registration.active.postMessage(message);
  } catch (error) {
    if (error instanceof Error) {
      throw new Error(`Failed to send message to service worker: ${error.message}`);
    }
    throw new Error(`Failed to send message to service worker: ${error}`);
  }
}


/**
 * Sends a message to the Service Worker and awaits a response.
 * @param {ServiceWorkerMessage} message - The message to be sent to the Service Worker.
 * @returns {Promise<any>} A promise that resolves with the response from the Service Worker.
 */
const sendToServiceWorkerAndGetReturn = async (message: serviceWorkerIndex.ServiceWorkerMessage): Promise<any> => {
  if (!('serviceWorker' in navigator)) {
    throw new Error('Service workers are not supported in this browser.');
  }

  return new Promise((resolve, reject) => {
      // Create a Message Channel
    const messageChannel = new MessageChannel();

      // Handle a message from the Service Worker
    messageChannel.port1.onmessage = (event) => {
      if (!event.data) return resolve(null);
      if (event.data.error) {
        reject(event.data.error);
      } else {
        resolve(event.data);
      }
    };

    // Send message to the Service Worker with the port for reply
    navigator.serviceWorker.ready.then(registration => {
      registration.active?.postMessage(message, [messageChannel.port2]);
    }).catch((error: Error | string) => {
      if (error instanceof Error) reject(new Error(`Failed to send message to service worker: ${error.message}`));
      else reject(new Error(`Failed to send message to service worker: ${error}`));
    });
  });
};

const getPathSuffix = (project: number, folder: string | null, shortName: string, extension: string): string => {
  return `_${project}_${folder ? `${folder}/` : ''}${shortName}${extension}`;
}

const getUrlLocalWithVersion = (project: number, folder: string | null, shortName: string, extension: string, version: string): string => {
  // '/local/_0_testFile.js?v=20240216130523886';
  return `/local/_${project}_${folder ? `${folder}/` : ''}${shortName}${extension}?v=${version}`;
}

const MLSWORKERTRACE = "mlsServiceWorkerTrace"; // redundant code
export const setTraceServiceWorker = (enable: boolean) => {
  serviceWorkerIndex.set("serviceWorker", MLSWORKERTRACE, enable ? 'true' : 'false')
    .catch((reason: any) => console.error(reason))
    .then(async () => {
      console.info(await getStatistics());
    })
}

export const getStatesOfCache = async (project: number): Promise<IFileInfoInCache[]> => {
  const cache: serviceWorkerIndex.IFilesRefInCache[] = await serviceWorkerIndex.getAllFilesRefInCache(project).catch(() => []);
  const rc: IFileInfoInCache[] = [];
  const keys = Object.keys(mls.stor.files);
  for (const key of keys) {
    const item = mls.stor.files[key];
    if (item.project !== project) continue;
    const localShortPath = serviceWorkerIndex.getLocalCacheKey(project, item.folder, item.shortName, item.extension);
    const value = cache.find((item2) => item2.key === localShortPath)?.value || "";
    const localCacheState = (value && value === item.versionRef) ? 'HIT' : 'MISS';
    rc.push({
      fileKey: key,
      localCacheState: item.inLocalStorage ? 'INDEVELOPMENT' : localCacheState
    });
  }
  return rc;
}

export interface IFileInfoInCache {
  fileKey: string;
  localCacheState: 'HIT' | 'MISS' | 'INDEVELOPMENT';
}

