/**
 * get requires on enhancement
 * return void or throw
 * @internal
 */
export const addPathsToTypescriptConfigIfNeed = async (file: mls.stor.IFileInfoBase): Promise<void> => {
  const enhInstance = await getEnhancementModule(file)
  .catch((e) => { console.error(`error on fireBeforeCompile: ${(e as Error).message}`); });
  if (mls.istrace) console.log(`fireBeforeCompile: _${file.project}_/l/${file.level}/${file.folder ? file.folder + '/' : ''}${file.shortName} enhancement instance: ${Boolean(enhInstance)}`);

  const requires = enhInstance?.requires;
  if (mls.istrace) console.log(`addPathsToTypescriptConfigIfNeed: ${requires ? JSON.stringify(requires) : 'no requires'}`);
  if (!requires) return;
  const op = monaco.languages.typescript.typescriptDefaults.getCompilerOptions();
  if (!op.paths) op.paths = {};
  let changed = false;
  for (const require of requires) {
    if (mls.istrace) console.log(`addPathsToTypescriptConfigIfNeed: require: ${JSON.stringify(require)}`);
    if (require.type !== "tspath") continue;
    if (op.paths[require.name] &&
      op.paths[require.name].length === 1 &&
      op.paths[require.name][0] === require.ref) continue;
    op.paths[require.name] = [require.ref];
    changed = true;
  }
  if (!changed) return;
  if (mls.istrace) console.log(`paths typescript config changed: ${JSON.stringify(op.paths)}`);
  monaco.languages.typescript.typescriptDefaults.setCompilerOptions(op);
  const modelTS: mls.editor.IModelTS | undefined = mls.l2.typescript.getModelTS(file.project, file.shortName, file.folder);
  if (modelTS?.compilerResults) modelTS.compilerResults.modelNeedCompile = true;
}
