const instanceCache: IDSInstanceCache = {};

interface IDSInstanceCache {
  [key: string]: DesignSystemIO;
}

/**
 * Returns a string that serves as a key for a given project and data source index.
 *
 * @param project The project number.
 * @param dsindex The index in design system array in project.
 * @returns A string that uniquely identifies the data source within the project.
 */
const getKeyDs = (project: number, dsindex: number): string => {
  const key = `_${project}_${dsindex}`;
  return key;
};

/**
 * Returns a DesignSystemIO instance for the given project, dsindex, and widgetIOName. If an instance is already cached, it returns the cached instance. Otherwise, it creates a new instance and caches it for future use.
 *
 * @param {number} project - The project number.
 * @param {number} dsindex - The index in design system array in project.
 * @param {string} widgetIOName - The name of the widgetIO.
 *
 * @returns {DesignSystemIO} - The DesignSystemIO instance for the given project, dsindex, and widgetIOName.
 */
export const getOrCreateDSInstanceIO = (project: number, dsindex: number, widgetIOName: string): DesignSystemIO => {
  const dskey = getKeyDs(project, dsindex);
  if (!instanceCache[dskey]) {
    const instance: DesignSystemIO = new (window as any).l2_html[widgetIOName](project, dsindex);
    // eslint-disable-next-line no-warning-comments
    // TODO alterar l2_html
    instanceCache[dskey] = instance;
  }
  return instanceCache[dskey];
};


