export const plugins: Map<string, IPluginIndexInstance> = new Map();

/**
 * Clear all plugins and loads all plugins of a project
 */
export const loadAll = async (projectID: number, clearOlds: boolean): Promise<void> => {
    // loop in mls.stor.files and load all plugins this project
  if (mls.istrace) console.time("loadAllPlugins");
  if (clearOlds) plugins.clear();
  const prefix = "plugin";
  const suffix = "Index";
  const extension = ".ts";
  const keys = Object.keys(mls.stor.files);
  let total = 0;
  let notLoaded = 0;
  for await (const key of keys) {
    const item = mls.stor.files[key];
    if (!(item.project === projectID &&
        item.shortName.startsWith(prefix) &&
        item.shortName.endsWith(suffix) &&
        item.extension === extension)) continue;
    if (mls.istrace) console.log(`loading plugin: ${key}`);
    // eslint-disable-next-line no-loop-func
    await loadPluginIndex(item).then((plugin) => {
      if (plugin) {
        plugins.set(key, plugin);
        total++;
      } else notLoaded++;
    }).catch((e) => {
      console.log(`error on load plugin _${item.project}_${item.shortName}: ${e.message || e}`);
    });
  }
  if (mls.istrace) console.timeEnd("loadAllPlugins");
  if (mls.istrace) console.log(`total plugins loaded: ${total}, not loaded: ${notLoaded}`);
}


/**
 * get all menu actions from plugins loaded of a project and scope
 * filter only the actions that user have authority
 */
export const getAllMenuActions = (projectID: number,
    filter: {scope: Scope | '*', auth: string | '*', groupByCategoryAndPriority: boolean}): MenuAction[] => {
  const result: MenuAction[] = [];
  if (!filter.scope) filter.scope = '*';
  if (!filter.auth) filter.auth = '*';
  if (!filter.groupByCategoryAndPriority) filter.groupByCategoryAndPriority = false;
  const keys = plugins.keys();
  for (const key of keys) {
    const item = plugins.get(key);
    if (!item) continue;
    const file: mls.stor.IFileInfo = mls.stor.files[key];
    if (file.project !== projectID) continue;
    try {
      const menu1: MenuAction[] = item.getMenus();
      if (!Array.isArray(menu1)) throw new Error("getMenu must return an array");
      for (const action of menu1) {
        if (mls.istrace && filter.scope === '*') console.log(`menu action: scope: ${action.scope}, auth: ${action.auth}`);
        if (filter.scope !== '*' && !action.scope.includes(filter.scope)) continue;
                // filter by auth, if filter.auth is null, show all
        if (filter.auth !== '*' && !action.auth.includes(filter.auth) && !action.auth.includes('*')) continue;
        action.widgetConfig = key;
        result.push(action);
      }
    } catch (e: Error | any) {
      console.log(`error on load plugin menu _${file.project}_${file.shortName}: ${e.message || e}`);
    }
  }
    // group by category and priority
  if (filter.groupByCategoryAndPriority) {
    result.sort((a, b) => {
      if (a.category === b.category) {
        if (a.priority === b.priority) return 0;
        return (a.priority ?? 0) > (b.priority ?? 0) ? 1 : -1;
      }
      if (a.category === null) return -1;
      if (b.category === null) return 1;
      return a.category > b.category ? 1 : -1;
    });
  }
  return result;
}

/**
 * get all hooks references from plugins loaded of a project
 */
export const getAllHooks = (projectID: number): HookAction[] => {
  const result: HookAction[] = [];
  const keys = plugins.keys();
  for (const key of keys) {
    const item = plugins.get(key);
    if (!item) continue;
    const file: mls.stor.IFileInfo = mls.stor.files[key];
    if (file.project !== projectID) continue;
    try {
      const hooks: HookAction[] = item.getHooks();
      if (!Array.isArray(hooks)) throw new Error("hooks is not an array");
      for (const action of hooks) {
        result.push(action);
      }
    } catch (e: Error | any) {
      console.log(`error on load plugin hook _${file.project}_${file.shortName}: ${e.message || e}`);
    }
  }
  return result;
}

/**
 *  get all services references from plugins loaded of a project
 */
export const getAllServices = (projectID: number): ServiceAction[] => {
  const result: ServiceAction[] = [];
  const keys = plugins.keys();
  for (const key of keys) {
    const item = plugins.get(key);
    if (!item) continue;
    const file: mls.stor.IFileInfo = mls.stor.files[key];
    if (file.project !== projectID) continue;
    try {
      const services: ServiceAction[] = item.getServices();
      if (!Array.isArray(services)) throw new Error("getServices must return an array");
      for (const action of services) {
        result.push(action);
      }
    } catch (e: Error | any) {
      console.log(`error on load plugin service _${file.project}_${file.shortName}: ${e.message || e}`);
    }
  }
  return result;
}

const loadPluginIndex = async (file: mls.stor.IFileInfoBase): Promise<IPluginIndexInstance | null> => {
  return new Promise<IPluginIndexInstance | null>((resolve, reject) => {
    const url = `/local/_${file.folder ? file.folder + '/' : ''}${file.project}_${file.shortName}?cacheBust=${Date.now()}`;
    import(url).then((module) => {
      const a = module.default;
      if (!a) return reject(new Error("not found default export in plugin index"));
      if (typeof a === 'string' && a === 'disabled') return resolve(null);
      if (typeof a !== 'object' || a === null) return reject(new Error("Default export is not an object or is null"));
      if (typeof a.getMenus !== "function") return reject(new Error("not found getMenus function in plugin index"));
      if (typeof a.getHooks !== "function") return reject(new Error("not found getHooks function in plugin index"));
      if (typeof a.getServices !== "function") return reject(new Error("not found getServices function in plugin index"));
      return resolve(a);
    }).catch((e) => {
      console.log(`loadPluginIndex error: ${e.message || e}`);
      return reject(new Error(e.message || e));
    })
  })
}

/**
 * Load all modules from widgets list
 * Used to register web components and make initialization.
 */
export const loadModules = async (widgets: string[]): Promise<void> => {
  const promises: Promise<any>[] = widgets.map(async widget => {
    const file = mls.actual[0].setFullName(widget).getStorFile();
    if (!file || isNaN(file.project) || file.project < 1 || !file.shortName) throw new Error(`invalid widget name: ${widget}`);
    const url = `/local/_${file.folder ? file.folder + '/' : ''}${file.project}_${file.shortName}`;
    return import(url)
      .then((a) => {
        if (typeof a !== 'object' || !a.pluginData) throw new Error("Plugin module must have export const pluginData: IPluginData = { ... }");
        const pluginData: IPluginData = a.pluginData;
        if (typeof pluginData.getSvg !== "function") throw new Error("not found getSvg function in pluginData");
        if (typeof pluginData.title !== "string") throw new Error("not found title string in pluginData");
      })
      .catch((e: Error | any) => {
        console.log(`loadModule error: ${e.message || e}`);
        throw new Error(e.message || e);
      });
  });
  await Promise.all(promises);
};

