import { mls } from "../../src/index";
import { base } from "./api";

export async function processOrgs(orgs: { [org: string]: mls.cbe.IOrgInfo }) {
  if (!orgs || (typeof orgs !== "object")) return;
  const keys = Object.keys(orgs);
  for await (const key of keys) {
    mls.stor.orgs[key] = orgs[key];
    for await (const prj of orgs[key].sett.projects) {
      await processProjects(prj);
    }
  }
}

export async function processProviders(providers: mls.cbe.Provider[]) {
  if (!providers || !Array.isArray(providers)) return;
  for await (const provider of providers) {
    mls.l0.addProviderConnected(provider);
  }
}

export async function processInits(inits: { [widget: string]: string }) {
  if (!inits || (typeof inits !== 'object')) return;
  const keys = Object.keys(inits);
  for await (const key of keys) {
    await processInit(key, inits[key]);
  }
}

async function processInit(widget: string, value: string) {
  if (!value) return;
  import(widget).then(async (a: any) => {
    if (typeof a.init !== "function") throw new Error(`not found init function in widget: ${widget}`);
    await a.init(value);
  }).catch((e) => {
    console.log(`init widget: ${widget}, error: ${e.message || e}`);
  })
}

async function processProjects(prj: mls.cbe.IPrj_settings): Promise<void> {
  if (!prj.files || typeof prj.files !== 'string') return;
  if (!prj.repository_lastModified) throw new Error(`repository_lastModified is missing for project ${prj.id}`);
  const prjInfo: mls.cbe.IPrjSourcesInfo | string = mls.common.zip.decodeAndDecompressBase64(prj.files) as mls.cbe.IPrjSourcesInfo | string;
  if (typeof prjInfo === 'string') throw new Error(`Error decoding files for project ${prj.id}, files is a string`);
  if (Array.isArray(prjInfo.filesInfo) === false) {
    console.error(`Error decoding files for project ${prj.id}, files not an array`);
    return;
  }
  for await (const file of prjInfo.filesInfo) {
    await processFile(file); // decompress
  }
  await mls.stor.server.updateProjectFilesInfo(prj.id, prjInfo, prj.repository_lastModified);
  delete prj.files;
}

async function processFile(file: mls.cbe.IPrjSourcesFiles) {
  if (!file.jsContent) return;
  const js = mls.common.zip.decodeAndDecompressBase64(file.jsContent);
  if (typeof js !== 'string') {
    console.error(`Error decoding jsContent for file ${file.shortPath}`);
    return;
  }
  file.jsContent = js;
}

export const clearQueryString = () => {
  const url = window.location.origin + window.location.pathname;
  window.history.replaceState(null, '', url);
};

export function getCookie(name: string): string | null {
  const value = `; ${document.cookie}`;
  const parts = value.split(`; ${name}=`);
  if (parts.length === 2) {
    return parts.pop()?.split(';').shift() || null;
  }
  return null;
}
