import { mls } from "../../src/index";

export const init = (editor: monaco.editor.IStandaloneCodeEditor) => {

  const myDefinitionProvider = {
    provideDefinition: async function(model: monaco.editor.ITextModel, position: monaco.Position):Promise<monaco.languages.LocationLink[] | null> {
      const word = model.getWordAtPosition(position);

      if (word) {
        const ret = await mls.l2.typescript.getRef(model, word.word);
        if (ret) {
          const pos = model.getPositionAt(ret.pos)
          return [{
            uri: monaco.Uri.parse(ret.uri),
            range: new monaco.Range(pos.lineNumber, pos.column, pos.lineNumber, pos.column + ret.len),
            pos: ret.pos
          } as any];
        }
      }
      return null;
    }
  };

  let alreadyRegistered = false;
  if (!alreadyRegistered) {
    alreadyRegistered = true;
    monaco.languages.registerDefinitionProvider('typescript', myDefinitionProvider);
  }

  editor.addAction({
    id: 'mls.openfile.here',
    label: 'Open file here',
    keybindings: [monaco.KeyMod.CtrlCmd | monaco.KeyMod.Shift | monaco.KeyCode.F12],
    contextMenuGroupId: 'navigation',
    contextMenuOrder: 1,
    run: async function(ed) {
      await runOpenFile(ed, false);
    }
  });

  editor.addAction({
    id: 'mls.openfile.nextto',
    label: 'Open file next to',
    keybindings: [monaco.KeyMod.CtrlCmd | monaco.KeyCode.F12],
    contextMenuGroupId: 'navigation',
    contextMenuOrder: 1,
    run: async function(ed) {
      await runOpenFile(ed, true);
    }
  });

  // editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.F12, async function() {
  //   const position = editor.getPosition();
  //   const model = editor.getModel();
  //   if (!model || !position) return;

  //   const definition = await myDefinitionProvider.provideDefinition(model, position);
  //   if (definition && definition[0]) {
  //     gotoDefinition(definition[0].uri, (definition[0] as any).pos || 0, true);
  //   }
  // });

  const runOpenFile = async (ed: monaco.editor.ICodeEditor, useAnotherSide: boolean) => {
    const position = ed.getPosition();
    const model = ed.getModel();
    if (!model || !position) return;
    const definition = await myDefinitionProvider.provideDefinition(model, position);
    if (definition && definition[0]) {
      gotoDefinition(ed, definition[0].uri, (definition[0] as any).pos || 0, useAnotherSide);
    }
  }

  const gotoDefinition = (ed: monaco.editor.ICodeEditor, uri: monaco.Uri, filePosition: number, useAnotherSide: boolean): void => {
    let side: 'left' | 'right' = mls.editor.findPositionOfEditor(ed);
    if (useAnotherSide) side = (side === 'left') ? 'right' : 'left';
    mls.actual[0].setFullName(uri.path.replace(/\//g, '').split(".")[0])
    const file = mls.actual[0].getStorFile();
    if (!file) return;
    const mm = mls.l2.typescript.getModelTS(file.project, file.shortName, file.folder);
    if (mm) {
      mls.events.fireFileAction('open', mm.storFile, side, undefined, undefined, undefined, undefined, 0);
      mls.events.fireMonacoAction('gotoPosition', mm.storFile, undefined, side, filePosition, 400);
    } else console.log('not found model in l2.editors: ', file, uri);
  }
}

