import { mls } from "../../src/index";

export interface ITripleSlashVariables {
  [key: string]: string;
}

export interface ITripleSlash {
  tagName: string;
  variables: ITripleSlashVariables;
}

const tagName = 'mls';
const requiredVars = ['enhancement', 'fileReference'];
const optionalVars = ['author'];

// ex /// <mls shortName='widget1' enhancement='config_ts_web-component' />
export const parseXMLTripleSlash = (line: string): ITripleSlash => {
  if (!line.startsWith('/// <')) throw new Error('line must start with "/// <" (triple slash and xml');
  const res = parseXML(line.substring(3).trim());
  if (typeof res === 'string') throw new Error(`invalid triple slash: ${res}`);
  if (res.tagName !== tagName) throw new Error(`invalid tag name: '${res.tagName}', use '${tagName}'`);
  requiredVars.forEach((varName) => {
    if (!res.variables[varName]) throw new Error(`missing required variable: "${varName}"`);
  });
  for (const varName in res.variables) {
    if (!requiredVars.includes(varName) && !optionalVars.includes(varName)) throw new Error(`invalid variable name: "${varName}"`);
  }
  return res;
}


// ex <tagName variable='text' variable2="text" />
const parseXML = (str: string): string | ITripleSlash => {
  const regex = /<(\w+)((?:\s+\w+(?:\s*=\s*(?:"[^"]*"|'[^']*'))?)*)\s*\/?>/;
  const match = str.match(regex);
  if (!match) return "XML invalid: use ex: <mls variable='text' />";
  const tagName2 = match[1];
  const variables: ITripleSlashVariables = {};
  const attributes = match[2].match(/\w+(?:\s*=\s*(?:"[^"]*"|'[^']*'))?/g) || [];
  for (let i = 0; i < attributes.length; i++) {
    const [name, value] = attributes[i].split('=');
    variables[(name || '?')] = value ? value.replace(/(^['"]|['"]$)/g, '') : '';
  }
  const text = str.replace(match[0], "").trim();
  if (text) return `XML text invalid: '${text}' use ex: <mls variable='text' />`;
  return { tagName: tagName2, variables };
}

/**
 * Changes the value of a variable in an XML/HTML string.
 * @param mfile - The model, will change first line
 * @param variableName - The name of the variable to change.
 * @param newValue - The new value for the variable.
 * @returns An object containing the modified string and a boolean indicating if the variable was successfully changed.
 * @example
 * ```
 * const input = "<tagName variable='text' variable2=\"text\" />";
 * const { modifiedString, success } = changeVariable(input, "variable", "newValue");
 * console.log(modifiedString); // Output: "<tagName variable='newValue' variable2=\"text\" />"
 * console.log(success); // Output: true
 * ```
 */
export const changeVariable = (model: mls.editor.IModelBase, variableName: string, newValue: string): boolean => {
  if (!model?.model) return false;
  const lines: string[] = (model.model.getValue() || '').split('\n');
  const line = lines[0];
  if (!line.startsWith('/// <')) throw new Error('line must start with "/// <" (triple slash and xml');

  const regex = new RegExp(`(${variableName}\\s*=\\s*["'])([^"']*)`, "i");
  const match = line.match(regex);

  if (!match) return false;

  lines[0] = line.replace(regex, `$1${newValue}`);
  model.model.setValue(lines.join(('\n')));
  return true;
}
