import { mls } from "../index";

export type CodeLenID = 'fileReferences' | 'helpAssistant';

export interface ICodeLenCommand {
  id: CodeLenID;
  title: string;
  jsComm?: string;
  refs?: string;
}

export interface ICodeLen {
  [line: number]: ICodeLenCommand[];
}

/**
 * A custom CodeLens provider that adds information about references.
 */
class CustomCodeLensProvider implements monaco.languages.CodeLensProvider {

  /**
   * An event that is emitted when the CodeLens provider has updated information.
   */
  public readonly onDidChange?: monaco.IEvent<this> | undefined;

  /**
   * Provide CodeLens items for the given document.
   * @param model The document for which CodeLens items should be provided.
   * @param token A cancellation token.
   * @returns An array of CodeLens items.
   */
  provideCodeLenses(model: monaco.editor.ITextModel, token: monaco.CancellationToken): monaco.languages.CodeLensList {
    const lenses: monaco.languages.CodeLens[] = this.getLenses(mls.editor.getModelById(model.id));
    return {
      lenses,
      dispose: () => {
        // not implemented
      }
    }
  }

  getLenses(modelBase: mls.editor.IModelBase | undefined): monaco.languages.CodeLens[] {
    const lenses: monaco.languages.CodeLens[] = [];
    if (!modelBase || !modelBase.codeLens) return lenses;
    const { level, position } = mls.editor.getInfoFromActiveInstance();
    // eslint-disable-next-line guard-for-in
    for (const slineNr in modelBase.codeLens) {
      const len: ICodeLenCommand[] = modelBase.codeLens[slineNr];
      const lineNr = Number(slineNr);
      for (let i = 0; i < len.length; i++) {
        const comm: ICodeLenCommand = len[i];
        const id = getCommandID(modelBase.model, comm.id, level, position) || '';
        lenses.push({
          range: {
            startLineNumber: lineNr,
            startColumn: 1,
            endLineNumber: lineNr + 1,
            endColumn: 1,
          },
          id: `mlsCodelens${lineNr}`,
          command: {
            id,
            title: comm.title,
            arguments: [modelBase.model, modelBase.storFile, lineNr],
          },
        });
      }
    }
    return lenses;
  }

  /**
   * Resolve a CodeLens item.
   * @param model The document for which the CodeLens item was provided.
   * @param codeLens The CodeLens item to resolve.
   * @param token A cancellation token.
   * @returns The resolved CodeLens item.
   */
  resolveCodeLens(model: monaco.editor.ITextModel, codeLens: monaco.languages.CodeLens, token: monaco.CancellationToken): monaco.languages.CodeLens {
    console.info(`resolveCodeLens ${model.uri.toString()}`, codeLens);
    return codeLens;
  }
}

let statusInitCodeLens: 'notloaded' | 'loaded' = 'notloaded';

/**
 * @internal
 */
export const initCodeLens = (): void => {
  if (statusInitCodeLens !== 'notloaded') return;
  monaco.languages.registerCodeLensProvider("typescript", new CustomCodeLensProvider());
  statusInitCodeLens = 'loaded';
}

interface ICommands {
  [key: string]: string | null;
}

export const commands: ICommands = {};

const getCommandID = (model: monaco.editor.ITextModel, id: CodeLenID, level: number, position: 'left' | 'right'): string | null => {
  const editor = mls.editor.instances[mls.editor.activeInstance];
  if (!editor) return '';
  const key = editor.getId() + ':' + id;
  if (commands[key]) return commands[key];

  function cmdFileReference(): string | null {
    const commandId = editor.addCommand(
      0,
      function(ctx: any, model: monaco.editor.ITextModel, storFile2: mls.stor.IFileInfo, lineNr: number) {
        mls.events.fireFileAction('fileReference', storFile2, position)
      },
      ""
    );
    return commandId;
  }

  function cmdhelpAssistant(): string | null {
    const commandId = editor.addCommand(
      0,
      function(ctx: any, model: monaco.editor.ITextModel, storFile2: mls.stor.IFileInfo, lineNr: number) {
        console.info('helpAssistant in monado on line ' + lineNr);
        mls.events.fireMonacoAction('helpAssistant', storFile2, getCodLenCommand(model, lineNr, id), position, lineNr)
      },
      ""
    );
    return commandId;
  }

  let commandId: string | null;
  switch (id) {
    case 'fileReferences': commandId = cmdFileReference(); break;
    case 'helpAssistant': commandId = cmdhelpAssistant(); break;
    default: throw new Error(`Unknown command id ${id}`);
  }

  commands[key] = commandId;
  return commandId;
}

const getCodLenCommand = (model: monaco.editor.ITextModel, lineNr: number, id: CodeLenID): ICodeLenCommand | undefined => {
  if (!model) return;
  const mm = mls.editor.getModelById(model.id);
  if (!mm) return;
  const lens: ICodeLenCommand[] = mm.codeLens[lineNr];
  if (lens) {
    for (const len of lens) {
      if (len.id === id) return len;
    }
  }

}

/**
 * add a line in monaco editor, 'codeLens' to Help user , ex '4 References'
 */
export const addCodeLen = (model: monaco.editor.ITextModel, lineNr: number, args: ICodeLenCommand): void => {
  if (!model) return;
  const mfile = mls.editor.getModelById(model.id);
  if (!mfile) return;
  if (!mfile.codeLens) mfile.codeLens = {};
  let lens: ICodeLenCommand[] = mfile.codeLens[lineNr];
  if (lens) {
    // clear old codeLens
    for (let i = 0; i < lens.length; i++) {
      if (lens[i].id === args.id) {
        lens.splice(i, 1);
        break;
      }
    }
  } else lens = [];
  lens.push(args);
  mfile.codeLens[lineNr] = lens;
  updateCodeLens(model);
};

/**
 * remove all lens in line
 */
export const removeCodeLen = (model: monaco.editor.ITextModel, lineNr: number): void => {
  if (!model) return;
  const mfile = mls.editor.getModelById(model.id);
  if (!mfile) return;
  if (!mfile.codeLens) mfile.codeLens = {};
  if (mfile.codeLens[lineNr]) {
    delete mfile.codeLens[lineNr];
    updateCodeLens(model);
  }
}

const updateCodeLens = (model: monaco.editor.ITextModel) => {
  const list: monaco.editor.ICodeEditor[] = mls.editor.findEditorsByModel(model);
  for (const ed of list) {
    ed.updateOptions({ codeLens: false });
    ed.updateOptions({ codeLens: true });
  }
}
