import { mls } from "../../src/index";

/**
 * Updates or adds a mapping in the import map.
 * If the shortName already exists, the mapping will be updated with the new URL.
 * If the shortName does not exist, a new mapping will be added.
 *
 */
export const updateImportMap = (key: string, url: string): void => {
    // Find the <script> tag for the import map
  const scriptTag = document.querySelector('script[type="importmap"]');

    // If the <script> tag is not found, create a new one
  if (!scriptTag) {
    const newScriptTag = document.createElement('script');
    newScriptTag.type = 'importmap';
    newScriptTag.textContent = JSON.stringify({ imports: { [key]: url }});
    document.head.appendChild(newScriptTag);
    return;
  }

    // If the <script> tag exists, parse the JSON content
  const importMap = JSON.parse(scriptTag.textContent || '{}');

    // Update or add the mapping using shortName and url
  importMap.imports = importMap.imports || {};
  if (importMap.imports[key] === url) return; // not changed
  importMap.imports[key] = url;

    // Update the content of the <script> tag
  scriptTag.textContent = JSON.stringify(importMap, null, 2);
}
