//
// CAA - Collab AI Agents
//

interface CAAOrchestration {
    name?: string; // optional agent name
    origin: string; // ex: "_100111_widget1"
    reference?: string; // Ex.: "_100111_widget1"
    enabledFunctions?: CAAFunction[];
    steps: CAAStep[];
}

type CAAStep =
    | PromptStep
    | UploadStep
    | TaskStep;

interface PromptStep {
    type: "prompt";
    assistant: string; // Ex.: "gpt_ts", "gpt_css", "gpt_requeriments"
    systemPrompt?: string;
    userPrompt?: string;
}

interface UploadStep {
    type: "upload",
    condiction: "only_if_more_recent",
    reference: string; // ex: "_100111_project.d.ts"
}

interface TaskStep {
    type: "task";
    reference: string; // Ex.: "update_file"
    args: string; // Ex.: ".ts", ".less", ".html"
}

interface CAAFunction {
    widget: "_100111_widget1"; // this widget will provider information to functions to execute
}
