// routines and functions to typescript

const MLSTSWORKERVERSION = "[MLSTSWORKERVERSION]";

export interface ICompilerResult {
  errors: monaco.languages.typescript.Diagnostic[];
  prodJS: string;
  prodDTS: string;
  prodMap: string;
  // devJS: string;
  // devTS: string;
  devDoc: string; /** json doc - jsDoc */
  trace: string[];
  // delay: number;
  modelVersion: number;
  cacheVersion: string,
  modelNeedCompile: boolean;
  errorEnhancementNotFound: boolean;
  imports: string[];
  decorators: string; // { [fieldName: string]: string[] };
  tripleSlashMLS?: mls.common.tripleslash.ITripleSlash;
}


export const getModelTS = (project: number, shortName: string, folder: string): mls.editor.IModelTS | undefined => {
  return mls.editor.models[mls.editor.getKeyModel(project, shortName, folder, 2)]?.ts;
}

