/**
 * query string examples:
 * https://collab.codes?source=google&code=4/0AY0e-g6hXZL_o1L7X7hVp6...&state=abc123xyz
 * https://collab.codes?source=google&error=access_denied&error_description=The+user+denied+access&state=abc123xyz
 */
/**
 * When returning from collab-auth, the access/refresh tokens arrive in the URL
 * fragment (#access_token=...&refresh_token=...). We hand them to the cbe
 * (action:authSession), which verifies the JWT and stores them as httpOnly
 * cookies — JavaScript never keeps the tokens. Then we strip the fragment so
 * the tokens don't linger in the URL/history.
 */
const handleCollabAuthCallback = async (): Promise<void> => {
  if (!location.hash || location.hash.indexOf('access_token=') === -1) return;
  const params = new URLSearchParams(location.hash.replace(/^#/, ''));
  const access_token = params.get('access_token') || '';
  const refresh_token = params.get('refresh_token') || '';
  // Remove the fragment (and the ?collabauth=1 marker) immediately.
  try {
    history.replaceState(null, '', location.pathname);
  } catch { /* ignore */ }
  if (!access_token) return;
  try {
    await mls.api.base.cbePost({ action: 'authSession', access_token, refresh_token } as any);
  } catch (e) {
    console.error('Error establishing collab-auth session', e);
  }
};

export const cbeLogin = async (): Promise<cbe.ResponseBase | undefined> => {
  await handleCollabAuthCallback();
  const baseProject: number = tryParseNumber((document.getElementById('collabNav1')?.getAttribute('initialproject')), 0);
  const actualProject: number = mls.actualProject || 0;
  const projectsLastModified = await mls.stor.localDB.getProjectsLastModified();

  let queryString: string = '';
  if (location.search.includes('source=')) {
    const lastState = localStorage.getItem('pluginCollabLogin') || '';
    queryString = encodeURIComponent(`${location.search}&lastState=${lastState}`);
  }

  const args: cbe.RequestLogin = {
    action: "login",
    queryString,
    baseProject,
    actualProject,
    projectsLastModified
  }
  try {
    const rc = await mls.api.base.cbePost(args) as unknown as cbe.ResponseLogin;
    await common.processOrgs(rc.orgs);
    await common.processInits(rc.inits);
    await common.processProviders(rc.providers);
    rc.inits = {};
    if (location.search.includes('source=')) {
      localStorage.removeItem('pluginCollabLogin');
      common.clearQueryString();
    }
    if (rc.alertMessage) window.collabMessages.add(rc.alertMessage, 'alert', { timeToClose: 5000 });
    if (rc.errorMessage) window.collabMessages.add(rc.errorMessage, 'error', { autoClose: false });
    return rc;
  } catch (e) {
    console.error(`Error on cbeLogin`, e);
    if (location.search.includes('source=')) {
      localStorage.removeItem('pluginCollabLogin');
      console.error(`queryString: '${queryString}'`);
      common.clearQueryString();
    }
    return undefined;
  }
}

