/**
 * save settings in project or
 * move project to another organization or
 * archive project (change archived_at)
 * 1. prepare the data in memory , aka mls.stor.orgs
 * 2. call the server to save the data
 * 3. see response if ok or not
 * @param project project number
 */
export const cbeSavePrjSettings = async (project: number): Promise<cbe.ResponseSavePrjSettings> => {

  const projectDetails: cbe.IPrj_settingsApi | undefined = mls.l5.getProjectDetails(project);
  if (!projectDetails) throw new Error(`Project ${project} not found`);
  if ('created_at' in projectDetails) {
    delete projectDetails.created_at;
  }
  if ('archived_at' in projectDetails) {
    delete projectDetails.archived_at;
  }
  if ('repository_lastModified' in projectDetails) {
    delete projectDetails.repository_lastModified;
  }
  if ('files' in projectDetails) {
    delete projectDetails.files;
  }
  const orgIndex = mls.l5.getProjectOrgIndex(project);
  if (!orgIndex) throw new Error('Project not found in organizations');
  const orgName = Object.keys(mls.stor.orgs)[orgIndex];

  const args: cbe.RequestSavePrjSettings = {
    action: "savePrjSettings",
    project,
    orgIndex,
    orgName,
    projectDetails
  }
  return mls.api.base.cbePost(args) as any as cbe.ResponseSavePrjSettings;
};

