import { cbe } from "../mls";

// access to store
export const prepareUrl = (base: string, args: any): string => {
  let sArgs = "";
  for (let prop in args) {
    // encodeURIComponent for one arg
    // encodeURI for all URI
    if (sArgs === "") {
      sArgs = prop + "=" + encodeURIComponent(args[prop]);
    } else {
      sArgs += "&" + prop + "=" + encodeURIComponent(args[prop]);
    }
  }
  return base + "?" + sArgs;
}

// RUM - Real User Monitoring
let rum: any = {};

const addRUMLoad = (repeat: number): void => {
  // https://developer.mozilla.org/en-US/docs/Web/API/Navigation_timing_API
  // https://stackoverflow.com/questions/47638595/calculate-the-estimated-page-load-time
  if (repeat > 100) return;
  setTimeout(() => {
    try {
      const perfData = window.performance.timing;
      let pageLoadTime = perfData.loadEventEnd - perfData.navigationStart; // time page Load, CSS and JS
      if (pageLoadTime < 0) return addRUMLoad(repeat + 1); // not ready
      rum.connectTime = perfData.responseEnd - perfData.requestStart; // time for connect to server
      rum.pageLoadTime = pageLoadTime;
      rum.renderTime = perfData.domComplete - perfData.domLoading; // time to render
    } catch (e) {
      // return;
    }
  }, 500);
}

const addRUMapi = (str: number, end: number, command: string) => {
  // rum[command] = Math.trunc(end - str);
  if (command === "api/loginAgain") addRUMLoad(1);
}


// type OnMessage = (msg: string, error: boolean, textStatus?: string, jqXHR?: JQueryXHR) => void;
type OnMessage = (msg: string, error: boolean) => void;

/**
 * use to get static files, ex: /ping, /mlsServiceWorker.js, /libs/*, /www/*, /monaco/*, / (index.html)
 */
export const get = (
  command: string,
  args: any = {},
  onMessage: OnMessage,
  // tryLoginAgain?: boolean,
): void => {
  if (Object.keys(rum).length > 0) {
    args.rum = JSON.stringify(rum);
    rum = {};
  }
  const str = performance.now();

  // let url = new URL(command, document.location.href);
  // url.search = new URLSearchParams(args).toString();
  fetch(prepareUrl(command, args))
    .then((response): void => {
      // if (
      //   tryLoginAgain &&
      //   response.status === 412 &&
      //   command.startsWith("api/login") === false
      // ) {
      //   loginAgain().then((success: boolean): void => {
      //     if (success) {
      //       return get(command, args, onMessage, false); // exec again, reentrance
      //     }
      //   });
      //   return onMessage("login error", true);
      // }
      if (response.status === 200) {
        response.text().then((data: string) => {
          addRUMapi(str, performance.now(), command);
          return onMessage(data, false);
        });
      } else {
        const msg: string =
          "internet or server error: " +
          response.status +
          ", " +
          response.statusText;
        mls.main.usermsg(msg);
        return onMessage(msg, true);
      }
    })
    .catch((error) => {
      const msg: string = typeof error === "string" ? error : "error " + error;
      mls.main.usermsg(msg);
      onMessage(msg, true);
    });
}

/**
 * use to get static files, ex: /ping, /mlsServiceWorker.js, /libs/*, /www/*, /monaco/*, / (index.html)
 */
export const getAsync = (
  command: string,
  args: any = {},
  // tryLoginAgain?: boolean,
): Promise<string> => {
  return new Promise<string>((resolve, reject) => {
    get(
      command,
      args,
      (msg: string, error: boolean) => {
        if (error) return reject(msg);
        return resolve(msg);
      },
      // tryLoginAgain,
    );
  });
}


export const cbePost = async (args: cbe.RequestBase): Promise<cbe.ResponseBase> => {
  let urlHttp = "https://on.collab.codes/exec";
  if (location.host === "collab.codes") urlHttp = "https://collab.codes/exec"; // old
  else if (location.host !== "on.collab.codes" && !location.host.endsWith(".collab.codes")) {
    // Runtime VM: localhost, *.collabcodes.com and client custom domains.
    // The 102034 server exposes a cbe-compatible /exec on the same origin
    // (see mls-102034 l1/server/layer_1_external/cbe).
    urlHttp = `${location.origin}/exec`;
  }

  let showMsg = true;
  try {
    const response = await fetch(urlHttp, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(args),
      credentials: 'include'
    });

    if (response.status !== cbe.HttpStatus.OK) {
      showMsg = false;
      throw (await getPostError(response, args));
    }
    const data = await response.json();
    if (!data) {
      throw new Error("No data on cbePost");
    }
    return data;

  } catch (error) {
    if (showMsg) console.error("Network or initiation error on cbePost: ", error);
    throw error; // Re-throw the error to be handled by the caller
  }
};

const getPostError = async (response: Response, args: cbe.RequestBase): Promise<Error> => {
  const data = await response.json()
  .catch(err => {
    console.error("Error on getPostError: ", err);
    return new Error(`No data on cbePost error: ${err}`);
  });

  const errorMsg = (typeof data.msg === 'string') ? data.msg : data.error || 'Unknown error';
  if (response.status === cbe.HttpStatus.BAD_REQUEST) {
    console.error(`Error on cbePost, status: ${response.status}, msg: ${errorMsg}, invalid args: `, JSON.stringify(args));
    return new Error(`Invalid args, msg: ${errorMsg}`);
  }
  if (response.status === cbe.HttpStatus.CONFLICT) {
    return new Error(`DomainError: ${errorMsg}`);
  }
  const msg = `Error on cbePost, status: ${response.status} - ${response.statusText}, error: ${errorMsg}`;
  console.error(msg);
  return new Error(msg);
}
