export const convertPathToClassName = (key: string): string => {
  // ex: 100111/a_test -> _100111_a_test
  const i1 = key.indexOf("/");
  if (i1 < 1) {
    return key;
  } else {
    return `_${key.replace("/", "_")}`;
  }
}


