import { mls } from "../index";


export function getBotContextVarsBeforeMessageSend(
  thread: mls.msg.Thread,
  messageText: string
): string[] {
  const vars = new Set<string>();

  for (const bot of thread.bots || []) {
    if (bot.status === "disabled") continue;

    for (const triggerEntry of bot.triggers || []) {
      if (triggerEntry.type !== "onNewMessage") continue;

      const conditions = triggerEntry.conditions || [];
      const msg = messageText.toLowerCase();
      const conditionResults = conditions.map(cond => {
        const value = cond.value.toLowerCase();
        switch (cond.type) {
          case "hasTag":
            return msg.includes(value.startsWith("#") ? value : `#${value}`);
          case "mention":
            return msg.includes(value.startsWith("@") ? value : `@${value}`);
          case "startsWith":
            return msg.startsWith(value);
          case "contains":
            return msg.includes(value);
          default:
            return false;
        }
      });

      const conditionsPassed = (triggerEntry.match || "any") === "all"
        ? conditionResults.every(Boolean)
        : conditionResults.some(Boolean);

      if (!conditionsPassed && conditions.length > 0) continue;

      const prompt = bot.llmPrompt || "";
      const matches = prompt.match(/{{\s*([\w\d_]+)\s*}}/g) || [];

      for (const match of matches) {
        const varName = match.replace(/{{\s*|\s*}}/g, "");
        vars.add(varName);
      }

      break;
    }
  }

  return Array.from(vars);
}

export interface ToolsBeforeSendMessage {
  toolName: string;
  args: Record<string, any>;
}

/**
 * Verifies which tools must be executed before sending a message to the bot.
 *
 * @param vars List of required tool calls for LLM prompt.
 *   Each item must follow one of these formats:
 *   - "toolName" → calls tool with no arguments (example: "getSystemInfo")
 *   - "toolName(arg1,arg2,...)" → calls tool with named arguments
 *     The arguments are resolved using keys from `myArgs`.
 *     Example: "toolGetDefs(shortName,projectId)"
 *
 * @param myArgs A dictionary of values used to resolve the argument names.
 *   Example: { shortName: "organismNav", projectId: "001" }
 *
 * @returns A list of tools with their resolved arguments to be executed.
 */
export function getBotContextVarsBeforeMessageSend2(
  vars: string[],
  myArgs: Record<string, any>
): ToolsBeforeSendMessage[] {
  const results: ToolsBeforeSendMessage[] = [];
  const ignoreList = ["botRecord"];

  for (const entry of vars) {
    if (ignoreList.includes(entry)) continue;
    const match = entry.match(/^(\w+)\(([^)]*)\)$/); // toolName(arg1,arg2,...)
    if (match) {
      const toolName = match[1];
      const argList = match[2]
        .split(",")
        .map(s => s.trim())
        .filter(Boolean);

      const args: Record<string, any> = {};
      for (const arg of argList) {
        args[arg] = myArgs[arg];
      }

      results.push({ toolName, args });
    } else {
      // Fallback: treat as tool with no args
      results.push({ toolName: entry, args: {}});
    }
  }

  return results;
}
