export const getShortPath = ({ level, shortName, extension, folder }:
  { level: number, shortName: string, extension: string, folder: string }): string => {
  return `l${level}/` +
      (folder === "" ? "" : `${folder}/`) +
      shortName + extension;
}

/**
 * @internal
 */
export const updateOrgs = (json: string): void => {
  const orgs2 = JSON.parse(json);
  if (!Array.isArray(orgs2)) console.error("Error in updateOrgs, orgs is not a array");
  // orgs2 , ex[ { VersionNumber: 1, key: "org/xx" , sett: {xxx} } ]
  for (const org of Object.keys(orgs2)) {
    const orgInfo = orgs2[org];
    if (!orgInfo.key || !orgInfo.sett || orgInfo.key.startsWith("org/") === false) continue;
    orgs[orgInfo.key] = orgInfo;
  }
}

export const getFileStorFromJson = (json: string, defaults:{ project?: number, level?: number, folder?: string, extension?: string }): IFileInfo | undefined => {
  let parsedJson: any;
  try {
    parsedJson = mls.common.safeParseArgs(json.trim());
  } catch (e) {
    return undefined;
  }
  if (!parsedJson || !parsedJson.shortName) return undefined;
  parsedJson.project = parsedJson.project ?? defaults.project; // default project
  if (!parsedJson.level) parsedJson.level = defaults.level ?? 2; // default level
  if (!parsedJson.folder) parsedJson.folder = defaults.folder ?? ""; // default folder
  if (!parsedJson.extension) parsedJson.extension = defaults.extension ?? ".ts"; // default extension
  return mls.stor.files[getKeyToFile(parsedJson)];
}

export const getKeyToFile = ({ project, level, shortName, folder, extension }: IFileInfoBase): string => {
  if (folder) return `${project}_${level}_${folder}/${shortName}${extension}`;
  return `${project}_${level}_${shortName}${extension}`;
};

// @deprecated use getKeyToFile
export const getKeyToFiles = (project: number, level: number, shortName: string, folder: string, extension: string): string => {
  if (folder) return `${project}_${level}_${folder}/${shortName}${extension}`;
  return `${project}_${level}_${shortName}${extension}`;
};

/**
 * return ex "_100111_/l2/folder1/file1.ts"
 */
export const convertFileToFileReference = (fileInfo: IFileInfoBase): string => {
  if (fileInfo.folder && fileInfo.folder !== "") {
    return `_${fileInfo.project}_/l${fileInfo.level}/${fileInfo.folder}/${fileInfo.shortName}${fileInfo.extension}`;
  } else {
    return `_${fileInfo.project}_/l${fileInfo.level}/${fileInfo.shortName}${fileInfo.extension}`;
  }
}

/**
 * convert , ex "_100111_/l2/folder1/file1.ts" to IFileInfoBase
 * return project = 0 if any error
 * extension = ".ts" or ".defs.ts"
 */
export const convertFileReferenceToFile = (fileReference: string): IFileInfoBase => {
  const rc = { project: 0, level: 2, shortName: "", folder: "", extension: "" };
  const parts = fileReference.split("/"); // ex: ["_100111_", "l2", "folder1", "file1.ts"] or ["file1.ts"]
  if (parts.length < 3 || parts[1].substring(0, 1) !== "l") return rc;
  let project = Number(parts[0].substring(1, parts[0].length - 1));
  let level = Number(parts[1].substring(1));
  if (isNaN(level) || isNaN(project)) return rc;
  let folder = "";
  if (parts.length > 2) {
    folder = parts.slice(2, parts.length - 1).join("/");
  }
  const filePart = parts[parts.length - 1];
  const firstDot = filePart.indexOf(".");
  if (firstDot === -1) return rc;
  let shortName = filePart.slice(0, firstDot);
  let extension = filePart.slice(firstDot);
  return { project, level, shortName, folder, extension };
}

/**
 * convert path to file information
 * ex: "_100111_/l2/folder1/file1.ts"
 * ex2: "_100111_/file1.ts"
 * ex3: "file1.ts"
 * ex4: "file1"
 */
export const getPathToFile = (path: string): IFileInfoBase => {
  const firstSlash = path.indexOf("/");
  let project = parseInt(path.slice(1, firstSlash - 1), 10);
  if (isNaN(project)) project = 0;
  const rest = path.slice(firstSlash + 1); // ex: "l2/folder1/file1.ts"
  const parts = rest.split("/");
  let level = 2; // default level
  let folder = ""; // default folder
  let extension = ".ts"; // default extension
  if (parts.length > 1) {
    // has level
    const levelStr = parts[0];
    if (levelStr.startsWith("l")) {
      const levelNum = parseInt(levelStr.slice(1), 10);
      if (!isNaN(levelNum)) level = levelNum;
    } else throw new Error(`Error in getPathToFile, level not valid: ${levelStr}`);

    if (parts.length > 2) {
      // has folder
      folder = parts.slice(1, parts.length - 1).join("/");
    }
  }
  const filePart = parts[parts.length - 1]; // ex: "file1.ts"
  const lastDot = filePart.indexOf(".");
  let shortName: string;
  if (lastDot === -1) {
    shortName = filePart;
  } else {
    shortName = filePart.slice(0, lastDot);
    extension = filePart.slice(lastDot);
  }
  return { project, level, shortName, folder, extension };
}

/**
 * delete in memory all Information of a project
 */
export const removeProjectInfo = (project: number): void => {
  const keys = Object.keys(files);
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (files[key].project === project) {
      delete files[key];
    }
  }
  delete projects[project];
}

/**
 * update many files in repositories
 * from one or many projects
 * from one or many drivers
 * @param {IFileInfo[]} fileInfos - list of files
 * @param {string} comments - comments to save on git
 */
export const setContents = async (fileInfos: IFileInfo[], comments: string | null): Promise<ISetContentsResult[]> => {
  let rc: ISetContentsResult[] = [];
  let refProjects: number[] = [...new Set(fileInfos.map(f => f.project))]; // remove duplicates
  const fileInfosLocalStorage: IFileInfo[] = [];
  for await (const project of refProjects) {
    let rcProject: ISetContentsResult[] = [];
    const fileInfos2: IFileInfo[] = [];
    for (const fileInfo of fileInfos) {
      if (fileInfo.project !== project) continue;
      const projectInfo = projects[project];
      if (!projectInfo) throw new Error(`project ${project} not found`);
      if ((fileInfo.project === 0) ||
          (fileInfo.project === mls.stor.LOCALPROJECTNUMBER) ||
          (fileInfo.inLocalStorage) ||
          (projectInfo.projectDriver === 'local')) fileInfosLocalStorage.push(fileInfo);
      else fileInfos2.push(fileInfo);
    }
    if (fileInfos2.length > 0) {
      rc.push({ project, result: await mls.stor.server.findDriverAndSetContents(project, fileInfos2, comments) });
    }
  }
  if (fileInfosLocalStorage.length > 0) {
    rc.push({ project: 0, result: await mls.stor.server.findDriverAndSetContents(0, fileInfosLocalStorage, comments) });
  }
  return rc;
}

/**
 * load or update one file in mls.stor.files
 */
export const addOrUpdateFile = async (
  { project, level, shortName, extension, versionRef, folder, updatedAt = undefined }:
  {project: number, level: number, shortName: string, extension: string, versionRef: string, folder: string, updatedAt?: string}
)
  : Promise<mls.stor.IFileInfo | undefined> => {
  if (!extension.startsWith(".")) throw new Error("loadInfoOneFile, extension must start with dot");
  const inLocalStorage = (project === 0) || (project === mls.stor.LOCALPROJECTNUMBER) || await mls.stor.localDB.existFile({ project, level, shortName, folder, extension });
  const key = getKeyToFile({ project, level, shortName, folder, extension });
  if (files[key]) {
    if (files[key].versionRef !== versionRef &&
      ((files[key].hasError || files[key].status !== "nochange") ||
       (files[key].inLocalStorage === false))) {
      if (files[key].inLocalStorage === false) {
        files[key].versionRef = versionRef;
      } else {
        files[key].newVersionRefIfOutdated = versionRef;
      }
      files[key].isLocalVersionOutdated = true;
      return files[key];
    } else {
      files[key].isLocalVersionOutdated = false;
      files[key].newVersionRefIfOutdated = undefined;
    }
    files[key].versionRef = versionRef;
    files[key].updatedAt = updatedAt;
  } else {
    const hasError = false;
    const isLocalVersionOutdated = false;
    const status = "nochange";
    files[key] = {
      project,
      level,
      shortName,
      folder,
      extension,
      status,
      hasError,
      versionRef,
      isLocalVersionOutdated,
      inLocalStorage,
      updatedAt: updatedAt,
      projectDependencies: null,
      getContent: mls.stor.server.findDriverAndGetContent,
      getValueInfo: mls.stor.localDB.getContentInfoOrNull,
      getHistory: mls.stor.server.findDriverAndGetHistory,
      getHistoryContent: function(ref: string): Promise<string | null> {
        return mls.stor.server.findDriverAndGetHistoryContent.call(this, ref);
      },
      saveContentInCacheIfNeed(): Promise<string | null> {
        return saveContentInCacheIfNeed.call(this);
      },
      async getOrCreateModel(): Promise<mls.editor.IModelBase> {
        // eslint-disable-next-line no-return-await
        return await getOrCreateModelForFile.call(this);
      }
    };

    if (inLocalStorage) {
      // update status and hasError
      const fileDB = await mls.stor.localDB.readFile({ project, level, shortName, folder, extension }).catch(() => null);
      if (fileDB && fileDB.fileInfo) {
        const fi = files[key];
        fi.status = fileDB.fileInfo.status;
        fi.hasError = fileDB.fileInfo.hasError;
      }
    }
  }
  return files[key];
}

async function saveContentInCacheIfNeed(this: IFileInfo): Promise<string | null> {
  const url = await mls.stor.cache.getURL(this.project, this.folder, this.shortName, this.extension, this.versionRef);
  if (url) return url;
  return mls.stor.cache.addIfNeed({
    project: this.project,
    folder: this.folder,
    shortName: this.shortName,
    version: this.versionRef,
    content: await this.getContent(),
    extension: this.extension,
  });
}

const pendingModels = new Map<string, Promise<mls.editor.IModelBase>>();

async function getOrCreateModelForFile(this: IFileInfo): Promise<mls.editor.IModelBase> {
  const models = mls.editor.getModel(this);
  if (models) return models as mls.editor.IModelBase;

  const key = convertFileToFileReference(this);
  const pendingModel = pendingModels.get(key);
  if (pendingModel) return pendingModel;

  const promise = Promise.resolve()
    .then(async (): Promise<mls.editor.IModelBase> => {
      const content = await this.getContent();
      if (typeof content !== 'string') throw new Error(`Error, content of ${key} must be a string to create model`);
      const result = await mls.editor.addModel(this, content);
      if (!result) throw new Error(`Error creating model for file ${key}, use getOrCreateModel only on source files`);
      return result;
    })
    .finally(() => {
      pendingModels.delete(key);
    });

  pendingModels.set(key, promise);
  return promise;
}

/**
 * change mls.stor.files for rename
 * don't change source
 */
export const renameFile = (storFile: mls.stor.IFileInfo, newName: mls.stor.IFileInfoBase): boolean => {
  const oldKey = mls.stor.getKeyToFile({ project: storFile.project, level: storFile.level, shortName: storFile.shortName, folder: storFile.folder, extension: storFile.extension });
  const newKey = mls.stor.getKeyToFile({ project: newName.project, level: storFile.level, shortName: newName.shortName, folder: storFile.folder, extension: storFile.extension });
  if (oldKey === newKey || mls.stor.files[newKey]) return false;
  storFile.shortName = newName.shortName;
  storFile.project = newName.project;
  mls.stor.files[newKey] = mls.stor.files[oldKey];
  delete mls.stor.files[oldKey];
  return true;
};

/**
 * Gets all unique project dependencies for a given project, excluding the project itself.
 * @param {number} project - The project ID to find dependencies for.
 * @returns {number[]} - An array of unique project dependencies.
 */
export const getProjectDependencies = (project: number): number[] => {
  const rc = new Set<number>();
  const fileKeys = Object.keys(files);
  for (const file of fileKeys) {
    for (const dep of files[file].projectDependencies || []) {
      if (dep !== project && dep > 1) rc.add(dep);
    }
  }
  return Array.from(rc);
};

// return true if project already loaded
export const isProjectLoaded = (project: number): boolean => {
  return (Boolean(projects[project]))
}

/**
 * Loads project dependencies if needed.
 *
 * @param {number} project - The project ID to analyze.
 * @param {boolean} [forceUpdate=false] - Whether to force a new calculation. Use after a change in dependencies.
 * @returns {Promise<number[]>} - A promise that resolves to a list of project dependencies loadeds
 */
export const loadProjectdependenciesInfoIfNeed = async (project: number, forceUpdate: boolean = false): Promise<number[]> => {
  if (mls.istrace) console.time('loadProjectdependenciesInfoIfNeed');
  const currentProject = projects[project];
  if (forceUpdate && currentProject) {
    currentProject.projectDependencies = null; // not calculated
  }
  const rc = await loadProjectDependenciesInfoIfNeed2(project, forceUpdate, 1);
  if (mls.istrace) console.timeEnd('loadProjectDependenciesInfoIfNeed');
  return rc;
}

const loadProjectDependenciesInfoIfNeed2 = async (project: number, forceUpdate: boolean, step: number): Promise<number[]> => {
  const currentProject = projects[project];
  if (currentProject === null) {
    // in loading project, wait
    if (step > 100) throw new Error(`Error, project ${project} in loading for a long time`);
    return new Promise<number[]>((resolve) => {
      setTimeout(() => {
        resolve(loadProjectDependenciesInfoIfNeed2(project, forceUpdate, step + 1)); // reentrance
      }, 100);
    });
  } else {
    if (!currentProject) return [];
    currentProject.projectDependencies = mls.stor.getProjectDependencies(project);
    const newProjectsDeps = currentProject.projectDependencies
        .filter(dd => !mls.stor.isProjectLoaded(dd));
    await Promise.all(newProjectsDeps.map(dep => mls.stor.server.loadProjectInfoIfNeeded(dep)));
    return newProjectsDeps;
  }
}

export async function getFiles(args: { project: number, shortName: string, folder: string, loadContent: boolean, level?: number }): Promise<IInfo> {
  const ret: IInfo = {
    ts: undefined,
    html: undefined,
    less: undefined,
    defs: undefined
  };
  const level: number = args.level ?? 2;

  ['.ts', '.html', '.less', '.defs.ts', '.test.ts'].forEach((ext: string) => {
    const key = getKeyToFile({ project: args.project, level, shortName: args.shortName, folder: args.folder, extension: ext });
    if (!files[key]) return;
    if (ext === '.ts') ret.ts = mls.stor.files[key];
    if (ext === '.html') ret.html = mls.stor.files[key];
    if (ext === '.less') ret.less = mls.stor.files[key];
    if (ext === '.defs.ts') ret.defs = mls.stor.files[key];
    if (ext === '.test.ts') ret.test = mls.stor.files[key];
  });
  if (!args.loadContent) return ret;
  return getFilesContent(ret);
}

/**
 * return list of files with .defs.ts not exists or not updated
 */
export function findFilesNeedingDefsUpdate(args: IFileInfoBase, forceBeforeAt?: Date): IFileInfo[] {
  const ret: IFileInfo[] = [];
  const level: number = args.level ?? 2;
  const shortNameFilter = args.shortName?.toLowerCase();
  const folderFilter = args.folder ? args.folder.toLowerCase() + "/" : undefined;

  const fileKeys = Object.keys(mls.stor.files);
  for (const key of fileKeys) {
    const file = mls.stor.files[key];
    if ((file.project !== args.project) ||
      (file.level !== level) ||
      (file.extension !== '.ts') ||
      (shortNameFilter && !file.shortName.toLowerCase().includes(shortNameFilter)) ||
      (folderFilter && !file.folder.toLowerCase().startsWith(folderFilter))) continue;

    const fileDefs = mls.stor.files[getKeyToFile({ ... file, extension: '.defs.ts' })];
    if (fileDefs) {
      const updatedAt = fileDefs.updatedAt || new Date(2000, 0, 1).toISOString();
      const isDefsBeforeBase: boolean = forceBeforeAt ? (new Date(updatedAt) < forceBeforeAt) : false;
      const isDefsBeforeTS: boolean = file.updatedAt ? (new Date(updatedAt) < new Date(file.updatedAt)) : false;
      if (!isDefsBeforeBase && !isDefsBeforeTS) continue; // defs is newer
    }
    ret.push(file);
  }
  return ret;
}


export async function getFilesContent(info: IInfo): Promise<IInfo> {
  async function getFile(file: mls.stor.IFileInfo | undefined): Promise<string | undefined> {
    if (!file) return undefined;
    const content = await file.getContent();
    if (typeof content !== 'string') throw new Error(`Error, content of ${file.shortName} must be a string`);
    return content;
  }

  const [ts, html, less, def, test] = await Promise.all([
    getFile(info.ts),
    getFile(info.html),
    getFile(info.less),
    getFile(info.defs),
    getFile(info.test)
  ]);
  return { ts: info.ts, tsContent: ts, html: info.html, htmlContent: html,
    less: info.less, lessContent: less, defs: info.defs, defsContent: def, test: info.test, testContent: test };
}


export interface IInfo {
    ts: mls.stor.IFileInfo | undefined,
    tsContent?: string;
    html: mls.stor.IFileInfo | undefined,
    htmlContent?: string;
    less: mls.stor.IFileInfo | undefined,
    lessContent?: string;
    defs: mls.stor.IFileInfo | undefined
    defsContent?: string;
    test?: mls.stor.IFileInfo | undefined;
    testContent?: string;
}

