import { mls } from "../../src/index";

/**
 * @internal
 */
export const getContent = async (fileInfo: mls.stor.IFileInfo): Promise<string | Blob | null> => {
  if (!fileInfo.inLocalStorage) return null;
  const { project, level, shortName, folder, extension } = fileInfo;
  return getContentFile(project, level, shortName, folder, extension);
};

/**
 * @internal
 */
export const getContentFile = async (project: number, level: number, shortName: string, folder: string, extension: string): Promise<string | Blob | null> => {
  const fileDB = await mls.stor.localDB.readFile({ project, level, shortName, folder, extension }).catch(() => null);
  if (fileDB && fileDB.info) return fileDB.info.content;
  else return null;
}

/**
 * use to set content or clear content in local storage
 */
export const setContent = async (fileInfo: mls.stor.IFileInfo, info: mls.stor.IFileInfoValue): Promise<boolean> => {
  fileInfo.inLocalStorage = (Boolean(info.content));
  if (info.content) await mls.stor.localDB.saveFile(fileInfo, info);
  else await mls.stor.localDB.removeItem(fileInfo);
  return true;
};

/**
 * @internal
 */
export const setContents = async (project: number, fileInfos: mls.stor.IFileInfo[]): Promise<boolean> => {
  if (!fileInfos || fileInfos.length < 1) return false;
  let rc = true;
  for await (const fileInfo of fileInfos) {
    const info: mls.stor.IFileInfoValue = fileInfo.getValueInfo ? (await fileInfo.getValueInfo()) : { content: null };
    if (await setContent(fileInfo, info) === false) rc = false;
  }
  return rc;
};

