/**
 * @internal
 */
export const listFilesProjectLocal = async (projectSearch: number): Promise<mls.cbe.IPrjSourcesFiles[]> => {
  if ((projectSearch !== 0) && (projectSearch !== mls.stor.LOCALPROJECTNUMBER)) throw new Error("projectSearch must be local Project");
  const rc: mls.cbe.IPrjSourcesFiles[] = [];
  const keys = await mls.stor.localDB.getKeysWithPrefix(mls.stor.localDB.getPrefixToLocalStorage());
  for await (const [i, key] of keys) {
    const parseKey = await mls.stor.localDB.getInfoFromLocalStorage(key);
    if (!parseKey) continue;
    const { project, level, shortName, folder, extension } = parseKey.fileInfo;
    if (project !== projectSearch) continue;
    const dbContent = await getContentFile(project, level, shortName, folder, extension);
    rc.push({
      shortPath: mls.stor.getShortPath({ level, shortName, extension, folder }),
      versionRef: (new Date()).toUTCString(),
      Length: dbContent ? (dbContent as any).length : 0,
    });
  }
  return rc;
}

/**
 * return only files been changed in local storage , ex. .ts files
 * return shortPath, ex: 'l2/file1' or 'l2/folder1/file1'
 */
export const listFilesInDevelopment = async (projectSearch: number, onlyExtension: string = ""): Promise<string[]> => {
  const rc: string[] = [];
  const keys = await mls.stor.localDB.getKeysWithPrefix(mls.stor.localDB.getPrefixToLocalStorage()).catch(() => []);
  for (const key of keys) {
    const { level, project, shortName, folder, extension } = mls.stor.localDB.parseKeyToFile(key);
    if (project !== projectSearch) continue;
    if (onlyExtension && extension !== onlyExtension) continue;
    if (folder) {
      rc.push(`l${level}/${folder}/${shortName}`);
    } else {
      rc.push(`l${level}/${shortName}`);
    }
  }
  return rc;
}

export interface IRetProjectDetails {
    project: number,
    module?: string,
}

export const getProjectDetails = (): IRetProjectDetails => {
  const str = localStorage.getItem("projectDetails");
  if (str) {
    try {
      return JSON.parse(str);
    } catch (err) {
      return { project: 0 };
    }
  }
  return { project: 0 };
}

export const setProjectDetails = (projectDetails: IRetProjectDetails): void => {
  localStorage.setItem("projectDetails", JSON.stringify(projectDetails));
}
