import { ChangeGroup } from "./editor.localHistory";

export function addVersion(currentContent: string, newContent: string): ChangeGroup[] {
  return compactChanges(addVersion2(currentContent, newContent));
}

function compactChanges(changes: ChangeGroup[]): ChangeGroup[] {
  const compacted: ChangeGroup[] = [];
  let i = 0;
  // order changes by startLine
  changes.sort((a, b) => a.startLine - b.startLine);

  while (i < changes.length) {
    const current = changes[i];
    const next = i + 1 < changes.length ? changes[i + 1] : null;

    // Check if the current group is 'deleted' and the next is 'new'
    if (current.type === "deleted" && next && next.type === "new") {
      // Check if they have the same line range
      if (current.startLine === next.startLine && current.endLine === next.endLine) {
        // Merge the two groups into a 'change' group
        const changeGroup: ChangeGroup = {
          id: generateUniqueId(),
          type: "change",
          startLine: current.startLine,
          endLine: current.endLine,
          // previousContent: current.previousContent,
          // currentContent: next.currentContent,
        };
        compacted.push(changeGroup);

        // Skip the next group as it has been merged
        i += 2;
        continue;
      }
    }

    // If no compacting occurred, add the current group as is
    current.previousContent = undefined;
    current.currentContent = undefined;
    compacted.push(current);
    i++;
  }

  return compacted;
}

export function addVersion2(currentContent: string, newContent: string): ChangeGroup[] {
  return adjustLineNumbers(addVersion3(currentContent, newContent));
}

function adjustLineNumbers(changes: ChangeGroup[]): ChangeGroup[] {
  return changes.map(change => {
    // Swap startLine and endLine if endLine is less than startLine
    if (change.endLine < change.startLine) {
      [change.startLine, change.endLine] = [change.endLine, change.startLine];
    }

    // Return the adjusted change group
    return change;
  });
}

export function addVersion3(currentContent: string, newContent: string): ChangeGroup[] {
  const oldLines = currentContent.split("\n");
  const newLines = newContent.split("\n");

  const lcsMatrix = createLCSMatrix(oldLines, newLines);

  const changes: ChangeGroup[] = [];
  let currentGroup: ChangeGroup | null = null;

  let i = oldLines.length;
  let j = newLines.length;

  while (i > 0 || j > 0) {
    if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
      i--;
      j--;
    } else if (j > 0 && (i === 0 || lcsMatrix[i][j - 1] >= lcsMatrix[i - 1][j])) {
      const lineContent = newLines[j - 1];
      if (!currentGroup || currentGroup.type !== "new") {
        if (currentGroup) changes.push(currentGroup);
        currentGroup = {
          id: generateUniqueId(),
          type: "new",
          startLine: j,
          endLine: j,
          previousContent: [],
          currentContent: [lineContent],
        };
      } else {
        currentGroup.endLine = j;
        currentGroup.currentContent!.push(lineContent);
      }
      j--;
    } else if (i > 0 && (j === 0 || lcsMatrix[i][j - 1] < lcsMatrix[i - 1][j])) {
      const lineContent = oldLines[i - 1];
      if (!currentGroup || currentGroup.type !== "deleted") {
        if (currentGroup) changes.push(currentGroup);
        currentGroup = {
          id: generateUniqueId(),
          type: "deleted",
          startLine: i,
          endLine: i,
          previousContent: [lineContent],
        };
      } else {
        currentGroup.endLine = i;
        currentGroup.previousContent?.push(lineContent);
      }
      i--;
    } else {
      const oldLine = oldLines[i - 1];
      const newLine = newLines[j - 1];
      if (!currentGroup || currentGroup.type !== "change") {
        if (currentGroup) changes.push(currentGroup);
        currentGroup = {
          id: generateUniqueId(),
          type: "change",
          startLine: i,
          endLine: i,
          previousContent: [oldLine],
          currentContent: [newLine],
        };
      } else {
        currentGroup.endLine = i;
        currentGroup.previousContent?.push(oldLine);
        currentGroup.currentContent!.push(newLine);
      }
      i--;
      j--;
    }
  }

  if (currentGroup) changes.push(currentGroup);

  return changes.reverse();
}

// Helper function to create the LCS matrix
function createLCSMatrix(oldLines: string[], newLines: string[]): number[][] {
  const m = oldLines.length;
  const n = newLines.length;
  const lcsMatrix: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (oldLines[i - 1] === newLines[j - 1]) {
        lcsMatrix[i][j] = lcsMatrix[i - 1][j - 1] + 1;
      } else {
        lcsMatrix[i][j] = Math.max(lcsMatrix[i - 1][j], lcsMatrix[i][j - 1]);
      }
    }
  }

  return lcsMatrix;
}

// Helper function to generate a unique ID for each change group
function generateUniqueId(): string {
  return Math.random().toString(36).substr(2, 9);
}

export function createDiffGroups(currentContent: string, newContent: string): ChangeGroup[] {
  const oldLines = currentContent.split("\n");
  const newLines = newContent.split("\n");
  
  const changes: ChangeGroup[] = [];
  let oldIndex = 0;
  let newIndex = 0;

  while (oldIndex < oldLines.length || newIndex < newLines.length) {
    if (oldIndex < oldLines.length && newIndex < newLines.length) {
      if (oldLines[oldIndex] !== newLines[newIndex]) {
        // Line is changed, create a separate 'change' group
        changes.push({
          id: generateUniqueId(),
          type: "change",
          startLine: oldIndex + 1,
          endLine: oldIndex + 1,
          previousContent: [oldLines[oldIndex]],
          currentContent: [newLines[newIndex]]
        });
      }
      oldIndex++;
      newIndex++;
    } else if (oldIndex < oldLines.length) {
      // Remaining old lines are 'deleted'
      const deletedLines: string[] = [];
      const startLine = oldIndex + 1;

      while (oldIndex < oldLines.length) {
        deletedLines.push(oldLines[oldIndex]);
        oldIndex++;
      }

      changes.push({
        id: generateUniqueId(),
        type: "deleted",
        startLine: startLine,
        endLine: startLine + deletedLines.length - 1,
        previousContent: deletedLines
      });
    } else if (newIndex < newLines.length) {
      // Remaining new lines are 'new'
      const newLinesContent: string[] = [];
      const startLine = newIndex + 1;

      while (newIndex < newLines.length) {
        newLinesContent.push(newLines[newIndex]);
        newIndex++;
      }

      changes.push({
        id: generateUniqueId(),
        type: "new",
        startLine: startLine,
        endLine: startLine + newLinesContent.length - 1,
        currentContent: newLinesContent,
        previousContent: []
      });
    }
  }

  // Adjust line numbers and separate non-continuous groups
  return splitNonContinuousGroups(changes);
}

// Splits non-continuous 'new' and 'deleted' changes into separate ChangeGroups
function splitNonContinuousGroups(changes: ChangeGroup[]): ChangeGroup[] {
  const adjustedChanges: ChangeGroup[] = [];
  changes.forEach(change => {
    if (change.type === "new" || change.type === "deleted") {
      let currentGroup: ChangeGroup | null = null;
      let lineIndex = change.startLine;

      // Split non-continuous lines into separate groups
      for (let i = 0; i < (change.previousContent || '').length || i < (change.currentContent?.length || 0); i++) {
        const currentLine = lineIndex + i;
        
        if (!currentGroup) {
          currentGroup = {
            ...change,
            startLine: currentLine,
            endLine: currentLine,
            previousContent: change.type === "deleted" ? [(change.previousContent || [])[i]] : [],
            currentContent: change.type === "new" ? [change.currentContent![i]] : [],
          };
        } else {
          // Check if the current line is continuous with the previous one
          if (currentLine !== currentGroup.endLine + 1) {
            adjustedChanges.push(currentGroup);
            currentGroup = {
              ...change,
              startLine: currentLine,
              endLine: currentLine,
              previousContent: change.type === "deleted" ? [(change.previousContent || [])[i]] : [],
              currentContent: change.type === "new" ? [change.currentContent![i]] : [],
            };
          } else {
            currentGroup.endLine = currentLine;
            if (change.type === "deleted") {
              currentGroup.previousContent?.push((change.previousContent || [])[i]);
            }
            if (change.type === "new") {
              currentGroup.currentContent!.push(change.currentContent![i]);
            }
          }
        }
      }

      if (currentGroup) adjustedChanges.push(currentGroup);
    } else {
      adjustedChanges.push(change);
    }
  });

  return adjustedChanges;
}

// Function to get the line changes between two models using Monaco's computeLinesDiff
function getMonacoDiff(originalContent: string, modifiedContent: string): monaco.editor.ILineChange[] | null {
  // Create models for original and modified content
  const originalModel = monaco.editor.createModel(originalContent, 'typescript');
  const modifiedModel = monaco.editor.createModel(modifiedContent, 'typescript');

  // Use computeLinesDiff to get line differences
  const diff = monaco.editor.createDiffEditor(document.createElement('div'), {
    ignoreTrimWhitespace: true, // Optionally ignore whitespace changes
    maxComputationTime: 5000,   // Timeout in milliseconds
  });
  diff.setModel({
    original: originalModel,
    modified: modifiedModel,
  });
  const result = diff.getLineChanges();

  // Dispose models after computing the diff to free up memory
  originalModel.dispose();
  modifiedModel.dispose();

  return result;
}