
/**
 * Creates a CRC32 lookup table.
 * @returns A Uint32Array containing the CRC32 lookup table.
 */
const createLookupTable = (): Uint32Array => {
  const table = new Uint32Array(256);

  for (let i = 0; i < 256; ++i) {
    let value = i;
    for (let j = 0; j < 8; ++j) {
      value = value & 1 ? 0xEDB88320 ^ (value >>> 1) : value >>> 1;
    }
    table[i] = value;
  }

  return table;
};

const crc32LookupTable = createLookupTable();

/**
 * Calculates the CRC32 of a given text.
 * @param text - The input text for which the CRC32 should be calculated.
 * @returns The CRC32 value as an unsigned number.
 * @example
 * ```
 * import { crc32 } from "./crc32";
 *
 * const text = "Sample text for CRC32 calculation";
 * const crcValue = crc32(text);
 *
 * console.log("CRC32:", crcValue.toString(16));
 * ```
 */
export const crc32 = (text: string): number => {
  let crc = -1;
  for (let i = 0; i < text.length; ++i) {
    crc = (crc >>> 8) ^ crc32LookupTable[(crc ^ text.charCodeAt(i)) & 0xFF];
  }

    // Inverts the bits of the result
  crc ^= -1;

    // Returns the CRC32 as an unsigned number
  return crc >>> 0;
};

