let lastScriptID = 10;

export const loadScriptOnDOM = (ref: string, context: string, parentElement: HTMLHeadElement | HTMLBodyElement, scriptID?: string): Promise<boolean> => {
    // ref= project id or js name, ex 100111_preview

  return new Promise<boolean>((resolve) => {

    if (!context) resolve(true);

    const script = document.createElement('script');
    if (!scriptID) {
      script.id = 'js_' + lastScriptID;
      lastScriptID++;
    } else {
      script.id = scriptID;
    }

        // script.type = "text/javascript";
    if (context.trim().startsWith('export')) script.type = "module";
    script.dataset.prjDeps = ref;
    const eventOnLoad = '\n' +
            script.id + '.dispatchEvent(' +
            'new CustomEvent("mlsload")' +
            ');';
        // if error dispatchEvent undefined , verify how much script with same id there in preview

    script.text = context + eventOnLoad + '\n//# sourceURL=_' + ref + "_.js";
    const msg = "Error on load javascript of " + ref;

        // console.log('Loading script', prj, eventOnLoad, context);

    function removeEvents() {
      window.removeEventListener('error', windowErrorHandler);
      script.removeEventListener('error', rejectHandler);
      script.removeEventListener('abort', rejectHandler);
      script.removeEventListener('mlsload', loadedHandler);
    }

    const windowErrorHandler = (event: ErrorEvent) => {
      event.preventDefault();
      console.error(msg, event.message, event);
      removeEvents();
      resolve(false);
    };
    window.addEventListener('error', windowErrorHandler);

    const rejectHandler = (event: ErrorEvent | UIEvent) => {
      console.error(msg, 'Please check the import statements:\n' + context);
      removeEvents();
      resolve(false);
    };
    script.addEventListener('error', rejectHandler);
    script.addEventListener('abort', rejectHandler);

    const loadedHandler = (ev: Event) => {
      removeEvents();
      resolve(true);
    };

    try {
      script.addEventListener('mlsload', loadedHandler);
      parentElement.appendChild(script);
            // resolve(true);
    } catch (e) {
      console.error(msg + ": ", e, `refs: ${ref}`, `context: ${context}`);
      removeEvents();
      resolve(false);
    }

  });

}
