import { ChangeGroup } from "./editor.localHistory";

export function addVersion(currentContent: string, newContent: string): ChangeGroup[] {
  const oldLines = currentContent.split("\n");
  const newLines = newContent.split("\n");

    // 1. Find common lines (patience matching)
  const matches = findPatienceMatches(oldLines, newLines);

  const changes: ChangeGroup[] = [];
  let currentGroup: ChangeGroup | null = null;

  let oldIndex = 0;
  let newIndex = 0;

    // 2. Iterate over matches and detect changes
  matches.forEach(match => {
    while (oldIndex < match.oldIndex || newIndex < match.newIndex) {
      if (oldIndex < match.oldIndex && newIndex < match.newIndex) {
          // Line modified
        if (isSmallChange(oldLines[oldIndex], newLines[newIndex])) { // Check if it's a small change
          if (!currentGroup || currentGroup.type !== "change") {
            if (currentGroup) changes.push(currentGroup);
            currentGroup = {
              id: generateUniqueId(),
              type: "change",
              startLine: oldIndex + 1,
              endLine: oldIndex + 1,
              previousContent: [oldLines[oldIndex]],
              currentContent: [newLines[newIndex]],
            };
          } else {
            currentGroup.endLine = oldIndex + 1;
            currentGroup.previousContent?.push(oldLines[oldIndex]);
            currentGroup.currentContent!.push(newLines[newIndex]);
          }
        } else {
            // Treat it as separate add/delete if the lines are significantly different
          if (currentGroup) changes.push(currentGroup);
          changes.push({
            id: generateUniqueId(),
            type: "deleted",
            startLine: oldIndex + 1,
            endLine: oldIndex + 1,
            previousContent: [oldLines[oldIndex]],
          });
          changes.push({
            id: generateUniqueId(),
            type: "new",
            startLine: newIndex + 1,
            endLine: newIndex + 1,
            previousContent: [],
            currentContent: [newLines[newIndex]],
          });
        }
        oldIndex++;
        newIndex++;
      } else if (oldIndex < match.oldIndex) {
          // Line deleted
        if (!currentGroup || currentGroup.type !== "deleted") {
          if (currentGroup) changes.push(currentGroup);
          currentGroup = {
            id: generateUniqueId(),
            type: "deleted",
            startLine: oldIndex + 1,
            endLine: oldIndex + 1,
            previousContent: [oldLines[oldIndex]],
          };
        } else {
          currentGroup.endLine = oldIndex + 1;
          currentGroup.previousContent?.push(oldLines[oldIndex]);
        }
        oldIndex++;
      } else if (newIndex < match.newIndex) {
          // Line added
        if (!currentGroup || currentGroup.type !== "new") {
          if (currentGroup) changes.push(currentGroup);
          currentGroup = {
            id: generateUniqueId(),
            type: "new",
            startLine: newIndex + 1,
            endLine: newIndex + 1,
            previousContent: [],
            currentContent: [newLines[newIndex]],
          };
        } else {
          currentGroup.endLine = newIndex + 1;
          currentGroup.currentContent!.push(newLines[newIndex]);
        }
        newIndex++;
      }
    }

      // Advance pointers to the next matching line
    oldIndex++;
    newIndex++;
  });

    // Capture remaining changes after the last match
  while (oldIndex < oldLines.length || newIndex < newLines.length) {
    if (oldIndex < oldLines.length && newIndex < newLines.length) {
      if (isSmallChange(oldLines[oldIndex], newLines[newIndex])) { // Small change detection
        if (!currentGroup || currentGroup.type !== "change") {
          if (currentGroup) changes.push(currentGroup);
          currentGroup = {
            id: generateUniqueId(),
            type: "change",
            startLine: oldIndex + 1,
            endLine: oldIndex + 1,
            previousContent: [oldLines[oldIndex]],
            currentContent: [newLines[newIndex]],
          };
        } else {
          currentGroup.endLine = oldIndex + 1;
          currentGroup.previousContent?.push(oldLines[oldIndex]);
          currentGroup.currentContent!.push(newLines[newIndex]);
        }
      } else {
          // Treat as separate add/delete for significantly different lines
        if (currentGroup) changes.push(currentGroup);
        changes.push({
          id: generateUniqueId(),
          type: "deleted",
          startLine: oldIndex + 1,
          endLine: oldIndex + 1,
          previousContent: [oldLines[oldIndex]],
        });
        changes.push({
          id: generateUniqueId(),
          type: "new",
          startLine: newIndex + 1,
          endLine: newIndex + 1,
          previousContent: [],
          currentContent: [newLines[newIndex]],
        });
      }
      oldIndex++;
      newIndex++;
    } else if (oldIndex < oldLines.length) {
      if (!currentGroup || currentGroup.type !== "deleted") {
        if (currentGroup) changes.push(currentGroup);
        currentGroup = {
          id: generateUniqueId(),
          type: "deleted",
          startLine: oldIndex + 1,
          endLine: oldIndex + 1,
          previousContent: [oldLines[oldIndex]],
        };
      } else {
        currentGroup.endLine = oldIndex + 1;
        currentGroup.previousContent?.push(oldLines[oldIndex]);
      }
      oldIndex++;
    } else if (newIndex < newLines.length) {
      if (!currentGroup || currentGroup.type !== "new") {
        if (currentGroup) changes.push(currentGroup);
        currentGroup = {
          id: generateUniqueId(),
          type: "new",
          startLine: newIndex + 1,
          endLine: newIndex + 1,
          previousContent: [],
          currentContent: [newLines[newIndex]],
        };
      } else {
        currentGroup.endLine = newIndex + 1;
        currentGroup.currentContent!.push(newLines[newIndex]);
      }
      newIndex++;
    }
  }

  if (currentGroup) changes.push(currentGroup);

  return changes;
}

  // Check if two lines have a small change based on similarity
function isSmallChange(line1: string, line2: string): boolean {
  return getLevenshteinDistance(line1, line2) <= Math.max(line1.length, line2.length) * 0.2;
}

  // Calculate Levenshtein distance between two strings
function getLevenshteinDistance(a: string, b: string): number {
  const matrix = Array.from({ length: a.length + 1 }, () => Array(b.length + 1).fill(0));

  for (let i = 0; i <= a.length; i++) matrix[i][0] = i;
  for (let j = 0; j <= b.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= a.length; i++) {
    for (let j = 1; j <= b.length; j++) {
      matrix[i][j] =
          a[i - 1] === b[j - 1]
            ? matrix[i - 1][j - 1]
            : Math.min(matrix[i - 1][j] + 1, matrix[i][j - 1] + 1, matrix[i - 1][j - 1] + 1);
    }
  }

  return matrix[a.length][b.length];
}

// Find unique line matches for Patience Diff algorithm
function findPatienceMatches(oldLines: string[], newLines: string[]): { oldIndex: number, newIndex: number }[] {
  const oldLineMap = buildLineMap(oldLines);
  const newLineMap = buildLineMap(newLines);

  const matches: { oldIndex: number, newIndex: number }[] = [];

  oldLineMap.forEach((oldIndexes, line) => {
    const newIndexes = newLineMap.get(line);
    if (oldIndexes.length === 1 && newIndexes && newIndexes.length === 1) {
      matches.push({ oldIndex: oldIndexes[0], newIndex: newIndexes[0] });
    }
  });

  return matches.sort((a, b) => a.oldIndex - b.oldIndex);
}

// Map the occurrences of each line to identify unique lines
function buildLineMap(lines: string[]): Map<string, number[]> {
  const lineMap = new Map<string, number[]>();
  lines.forEach((line, index) => {
    if (!lineMap.has(line)) lineMap.set(line, []);
    lineMap.get(line)!.push(index);
  });
  return lineMap;
}

// Helper function to generate a unique ID for each change group
function generateUniqueId(): string {
  return Math.random().toString(36).substr(2, 9);
}
