export const tryParseNumber = (value: string | undefined | null, defaultValue: number): number => {
  if (!value) return defaultValue;
  const number = Number(value);
  return isNaN(number) ? defaultValue : number;
}

export function safeParseArgs(args: string): Record<string, any> {
  // Accepts:
  // { a: 5, b: abc }
  // a:5,b:4
  // a=5, b=4
  // Also accepts bareword string values: folder: agents
  if (!args) throw new Error("No args provided");

  let input = args.trim();

  // Try strict JSON first
  if (input.startsWith("{")) {
    try {
      return JSON.parse(input);
    } catch {
      // Fall through to lenient parsing
    }
  }

  // Normalize separators: a=1 -> a:1
  if (input.includes("=") && !input.includes(":")) {
    input = input.replace(/([a-zA-Z0-9_]+)\s*=/g, "$1:");
  }

  // Ensure braces
  if (!input.startsWith("{")) input = `{${input}}`;

  // Quote keys: { a:1, b:2 } -> { "a":1, "b":2 }
  input = input.replace(/([{,]\s*)([a-zA-Z0-9_]+)\s*:/g, '$1"$2":');

  // Convert simple single-quoted strings to double-quoted strings
  // e.g. { a: 'hello' } -> { "a":"hello" }
  input = input.replace(/'([^'\\]*(?:\\.[^'\\]*)*)'/g, (_, s) => `"${s.replace(/"/g, '\\"')}"`);

  // Quote bareword values (strings without quotes), but keep numbers/booleans/null as-is
  // e.g. { "folder": agents } -> { "folder":"agents" }
  input = input.replace(
    /:\s*([A-Za-z_][A-Za-z0-9_./-]*)(\s*)(?=[,}])/g,
    (full, value: string, ws: string) => {
      const lower = value.toLowerCase();
      const isKeyword = (lower === "true") || (lower === "false") || (lower === "null");
      return isKeyword ? `:${value}${ws}` : `:"${value}"${ws}`;
    }
  );

  try {
    return JSON.parse(input);
  } catch (e) {
    throw new Error("Invalid args format, cannot parse.");
  }
}

export function argsValidator(
  args: Record<string, any>,
  schema: Record<string, { type: string, description?: string; optional?: boolean }>
): void {
  for (const key in schema) {
    if (Object.prototype.hasOwnProperty.call(schema, key)) {
      const isOptional = (schema[key].optional === true);

      if (!(key in args)) {
        if (!isOptional) {
          throw new Error(`Missing argument: ${key}`);
        }
        continue; // ok se for opcional
      }

      const expectedType = schema[key].type;
      const actualType = typeof args[key];

      if (expectedType !== actualType) {
        throw new Error(`Invalid type for argument '${key}': expected '${expectedType}', got '${actualType}'`);
      }
    }
  }
}
