function getFullName(this: IActual): string {
  if (this.project === 1) return this.path || "";
  return `_${(this.project || 1).toString()}_${this.path}`;
}

function getStorFileBase(this: IActual): stor.IFileInfoBase {
  const rc = { project: this.project || 1, level: this.level, shortName: "", folder: "", extension: "" };
  if (rc.level === 0) rc.level = 2; // default to level 2 if not set
  if (!this.project || this.project < 1 || !this.path) return rc;
  // splice path in folder, shortName and extension
  const sp = this.path.split('/').filter(Boolean); // split and remove empty
  const shortNameAndExtension = sp.pop() || "";
  if (sp.length > 0 && sp[0] === "l2") {
    sp.shift(); // remove l2
    this.level = 2;
  } else if (sp.length > 0 && sp[0] === "l1") {
    sp.shift(); // remove l1
    this.level = 1;
  }
  const shortName = shortNameAndExtension.split('.')[0] || "";
  if (!shortName) return rc; // no shortName, no file
  const folder = sp.join('/') || "";
  const extension = shortNameAndExtension.includes(".") ? "." + (shortNameAndExtension.split(".").pop() ?? "") : ".ts";
  return { ...rc, shortName, folder, extension };
}

function getStorFile(this: IActual): stor.IFileInfo | undefined {
  const fileBase = getStorFileBase.call(this);
  const key = stor.getKeyToFile(fileBase);
  return stor.files[key];
}

function setFullName(this: IActual, value: string): IActual {
  if (!value) {
    value = "";
  }
  value = value.trim();
  if (value.startsWith("_")) {
    let pr = value.substring(1).split("_")[0];
    let prID: number = Number(pr);
    if (isNaN(prID)) prID = 0; // error
    this.project = prID;
    this.path = value.substring(pr.length + 2);
  } else {
    this.project = 1;
    this.path = value;
  }
  return this;
}
