import { mls } from "../../src/index";


export type MindMapNodePosition = 'left' | 'right' | 'top' | 'bottom';

/**
 * Size hints for mind map nodes.
 * - 'line': Node is a single line, typically used for small labels or titles.
 * - 'panel': Node is a panel, suitable for displaying more information.
 * - 'full': Node occupies full space, used for larger content or detailed views.
 *   in full mode, the component have to handle scrolling, search and filtering.
 */
export type MindMapNodeSizeHint = 'line' | 'panel' | 'full';

export interface MindMapNodeItem {
    id: string;
    label: string;
    position?: MindMapNodePosition;
    sizeHint?: MindMapNodeSizeHint;
    children?: string[]; // List of child node IDs, ex: ['page/table/user', 'page/table/posts']
}

export interface MindMapNodeBase {
    id: string;
    label: string;
    related?: string[]; // List of related node types
    element?: string; // Optional element type for rendering, ex: 'widget-mindmap-project'
}

/**
 * Helper class for mind map node path parsing and formatting.
 */
export class MindMapNodePathInput {
  domain: string;
  entity?: string;
  relation?: string;

  constructor(domain: string, entity?: string, relation?: string) {
    this.domain = domain;
    this.entity = entity;
    this.relation = relation;
  }

  toString(): string {
    let path = this.domain;
    if (this.entity) path += `/${this.entity}`;
    if (this.relation) path += `/${this.relation}`;
    return path;
  }
}


/**
 * Get mind map nodes based on the provided path.
 *
 * This function resolves the mind map nodes based on the domain and optional entity/relation.
 * It uses registered resolvers to fetch the appropriate nodes.
 * @param path Path input for mind map nodes, should follow the structure: domain[/entity][/relation]
 * @returns
 */
export async function getMindMapNodes(path: MindMapNodePathInput): Promise<(MindMapNodeItem[])> {
  let result: MindMapNodeItem[] = [];
  if (!path || !path.domain) {
    throw new Error('Invalid path input. Path must have a domain.');
  }
  const type = path.domain;

  // add base
  const baseNode = baseResolvers[type];
  if (!baseNode) throw new Error(`No base resolver found for mind map type: ${type}`);
  result.push({
    id: baseNode.id,
    label: baseNode.label,
  });

  // find all bases and add static related nodes
  const keys = Object.keys(baseResolvers);
  for (const key of keys) {
    const base = baseResolvers[key];
    if (base.related && base.related.includes(type)) {
      result.push({
        id: `${base.id}/${path.domain}`,
        label: base.label,
        position: 'left',
        sizeHint: 'line',
      });
    }
  }

  // add dynamic resolvers
  if (!dynamicResolvers[type]) throw new Error(`No dynamica resolvers found for mind map type: ${type}`);
  const function1 = dynamicResolvers[type];
  if (!function1) throw new Error(`No dynamic resolver found for mind map type: ${type}`);
  const dynResult = await function1(path);
  if (!Array.isArray(dynResult)) throw new Error(`Dynamic resolver for type ${type} did not return an array`);
  result = [...result, ...dynResult];

  return result;
}

export const baseResolvers: Record<string, MindMapNodeBase> = {};
export const dynamicResolvers: Record<string, ((path: MindMapNodePathInput) => Promise<MindMapNodeItem[]>)> = {};

export function addBase(type: string, node: MindMapNodeBase) {
  baseResolvers[type] = node;
}

export function addDynamic(type: string, fn: (path: MindMapNodePathInput) => Promise<MindMapNodeItem[]>) {
  dynamicResolvers[type] = fn;
}
