/**
 * find project in memory and return the organization index
 * @param prjID
 * @returns organization index or undefined if not found
 */
export const getProjectOrgIndex = (prjID: number): number | undefined => {
  return mls.l5_common.getProjectOrganizationIndex(mls.stor.orgs, prjID);
}

export const getProjectDetails = (prjID: number): cbe.IPrj_settings | undefined => {
  return mls.l5_common.getProjectDetails(mls.stor.orgs, prjID);
}

export const getProjectSettings = (prjID: number): cbe.IProjectInfo | undefined => {
  return mls.l5_common.getProjectSettings(mls.stor.orgs, prjID);
}

export const setProjectSettings = (prjID: number, settings: cbe.IProjectInfo) => {
  mls.l5_common.setProjectSettings(mls.stor.orgs, prjID, settings);
}

export const getBaseProject = (prjID: number): number => {
  const deps = mls.l5.getProjectDetails(prjID)?.prj_dependencies;
  if (deps && deps[0]) return deps[0];
  return 0;
}

export const getProjectDependencies = (prjID: number, addParentPrj: boolean): number[] => {
  const detPrj: cbe.IPrj_settings | undefined = mls.l5.getProjectDetails(prjID);
  let dep: number[] = (detPrj?.prj_dependencies) ? [...detPrj.prj_dependencies] : [];
  if (!dep) dep = [];
  if (addParentPrj) dep.push(prjID);
  return dep;
}

export const getOrgsName = (): string[] => {
  return mls.l5_common.getOrgsName(mls.stor.orgs);
}

export const getProjectsInOrg = (orgIndex: number): number[] => {
  return mls.l5_common.getProjectsInOrg(mls.stor.orgs, orgIndex);
}

/**
 * get configurations of the project
 */
export async function getProjectConf(projectID: number): Promise<mls.l5_common.ProjectConfig> {
  if (!projectID) throw new Error('Invalid project');
  const keyToFile = mls.stor.getKeyToFile({ project: projectID, level: 5, shortName: mls.l5_common.FILENAMEPROJECTCONFIG, folder: '', extension: '.json' });
  const file = mls.stor.files[keyToFile];
  if (!file) throw new Error('No file project config');
  const src: string | Blob | null | undefined = await file.getContent();
  if (src === null || src === undefined) throw new Error('Invalid value of config');
  if (typeof src !== 'string') throw new Error('Config file must be string');

  try {
    const config: mls.l5_common.ProjectConfig = JSON.parse(src);
    return config;
  } catch (error: any) {
    throw new Error(`Error parsing config JSON: ${error.message}`);
  }
}

export async function updateProjectConf(projectID: number, config: mls.l5_common.ProjectConfig): Promise<void> {
  if (!projectID) throw new Error('Invalid project');
  const keyToFile = mls.stor.getKeyToFile({ project: projectID, level: 5, shortName: mls.l5_common.FILENAMEPROJECTCONFIG, folder: '', extension: '.json' });
  const file = mls.stor.files[keyToFile];
  if (!file) throw new Error('No file project config');
  await mls.stor.localStor.setContent(file, {
    contentType: 'string',
    content: JSON.stringify(config, null, 2)
  });
}
