import { mls } from "../../src/index";
import { IHistory } from "./stor";


/**
 * Abstract base class for driver I/O operations.
 * This serves as the blueprint for all driver I/O classes.
 */
export abstract class DriverIOBase {

  /**
   * The project ID.
   */
  public abstract project: number;

  /**
   * The short name identifier for the driver.
   */
  public abstract shortName: mls.cbe.Provider;

  /**
   * The version of the driver.
   */
  public abstract driverVersion: string;

  /**
   * Retrieves content from the repository for multiple files.
   *
   * @param {number} project - The project ID.
   * @param {mls.stor.IFileInfo[]} fileInfos - Array of file information objects. All fileInfo must be the same project
   * @returns {Promise<mls.stor.IRegGetContents[]>} - Promise resolving to an array of file contents.
   */
  public abstract getContents: (project: number, fileInfos: mls.stor.IFileInfo[]) => Promise<mls.stor.IRegGetContents[]>;

  /**
   * Sets content to the repository for multiple files.
   * Preferably performs an all-or-nothing update.
   *
   * @param {number} project - The project ID.
   * @param {mls.stor.IFileInfo[]} fileInfos - Array of file information objects. All fileInfo must be the same project.
   * @param {string | null} comments - Comments for the update.
   * @returns {Promise<boolean>} - Promise resolving to true if successful, false otherwise.
   */
  public abstract setContents: (project: number, fileInfos: mls.stor.IFileInfo[], comments: string | null) => Promise<boolean>;

  /**
   * Loads information about files for a specific project.
   *
   * @param {number} project - The project ID.
   * @returns {Promise<mls.api.IPrjSourcesFiles[]>} - Promise resolving to an array of project files information.
   */
  public abstract loadFilesInfo(project: number): Promise<mls.cbe.IPrjSourcesFiles[]>;

  /**
   * Retrieves the history of a file. Returns null if there's no implementation or if retrieval is not possible.
   *
   * @param {mls.stor.IFileInfo} file - The file information object.
   * @returns {Promise<IHistory[] | null>} - Promise resolving to an array of file history records or null if not available.
   */
  public abstract getHistory(fileInfo: mls.stor.IFileInfo): Promise<IHistory[] | null>;

  /**
   * Retrieves the content of a file from its history.
   *
   * @param {mls.stor.IFileInfo} file - The file information object.
   * @param {string} ref - The reference ID for the historical content.
   * @returns {Promise<string | null>} - Promise resolving to the file content or null.
   */
  public abstract getHistoryContent(fileInfo: mls.stor.IFileInfo, ref: string): Promise<string | null>;

  /**
   * get url for file in persistent site, ex: www.github.com/xxx
   */
  public abstract getUrl(file: mls.stor.IFileInfo): string;

  /**
   * get actual version of files in repository
   */
  public abstract getVersionFromFiles(options:{owner: string, repo: string, branchName: string, files: mls.stor.IFileInfo[]}): Promise<{[key: string]: string } | undefined>;

  /**
   * Checks if a branch exists in the specified repository.
   *
   * @param {string} owner - The owner or organization of the repository.
   * @param {string} repo - The name of the repository.
   * @param {string} branchName - The name of the branch to check.
   * @returns {Promise<boolean>} - A promise that resolves to `true` if the branch exists, otherwise `false`.
   */
  public abstract checkBranchExistence(owner: string, repo: string, branchName: string): Promise<boolean>;

  /**
   * create new branch in repository, before save files or include commits
   * @param {Object} options - The options for creating the pull request.
   * @param {string} options.owner - The owner or organization of the repository.
   * @param {string} options.repo - The name of the repository.
   * @param {string} options.branch - The name of the branch to create from.
   * @param {string} options.newBranch - The name of the new branch to create.
   * @param owner organization or user
   * @param repo repository name, ex 'mls-100111'
   * @param newBranch ex 'issue-123'
   */
  public abstract createNewBranch(option: {
    owner: string, repo: string, branch:string, newBranch: string}): Promise<boolean>;

  /**
   * Creates a pull request in a repository.
   *
   * @param {Object} options - The options for creating the pull request.
   * @param {string} options.owner - The owner or organization of the repository.
   * @param {string} options.repo - The name of the repository.
   * @param {string} options.title - The title of the pull request.
   * @param {string} options.description - The description of the pull request.
   * @returns {Promise<boolean>} - A promise that resolves to a boolean indicating whether the pull request was successfully created.
   */
  public abstract createPullRequest(options: {
    owner: string,
    repo: string,
    title: string,
    description: string
  }): Promise<boolean>;

  /**
   * Reviews a pull request by either approving or rejecting it.
   *
   * @param {Object} options - The options for reviewing the pull request.
   * @param {string} options.owner - The owner or organization of the repository.
   * @param {string} options.repo - The name of the repository.
   * @param {string} options.branch - The name of the branch.
   * @param {string} options.idRequest - The ID of the pull request to review.
   * @param {boolean} options.isApproved - Indicates whether the pull request is approved (true) or rejected (false).
   * @returns {Promise<boolean>} - A promise that resolves to a boolean indicating the success of the operation.
   */
  public abstract reviewPullRequest(options:
    {owner: string, repo: string, branch:string, idRequest: string, isApproved: boolean}
   ): Promise<boolean>;

  /**
   * list pull requests of repository
   * @param owner organization or user
   * @param repo repository name, ex 'mls-100111'
   */
  public abstract listPullRequests(owner: string, repo: string): Promise<IPullRequest[]>;

  /**
   * list forks of repository
   * @param owner organization or user
   * @param repo repository name, ex 'mls-100111'
   */
  public abstract listForks(owner: string, repo: string): Promise<IFork[]>;

  /**
   * return list of branches of repository
   * @param owner organization or user
   * @param repo repository name, ex 'mls-100111'
   */
  public abstract listBranches(owner: string, repo: string): Promise<IBranch[]>;

  /**
   * get user information
   */
  public abstract getUserInfo(): Promise<IInfo>;

  /**
   * get organizations of user, don't return owner organization
   * @param login login name, get from getUserInfo method
   */
  public abstract getOrganizations(login: string): Promise<IOrg[]>;

  /**
   * create repository on create new project process
   * @param login  login name, get from getUserInfo method
   * @param repo
   * @param organization organization or user
   * @param description description of repository
   * @param visibility 'PUBLIC', 'PRIVATE' or 'INTERNAL'
   * @returns true if success
   */
  public abstract createRepository(login: string, repo: string, organization: string, description: string, visibility: 'PUBLIC' | 'PRIVATE' | 'INTERNAL'): Promise<boolean>;

  /**
   * delete repository
   * @param repo repository name
   * @param organization organization or user
   * @returns true if success
   */
  public abstract deleteRepository(repo: string, organization: string): Promise<boolean>;

  /**
   * duplicate repository, create a fork in the organization or user , for changes and tests
   * @param login login name, get from getUserInfo method
   * @param repoOri repository name to fork
   * @param orgOri  organization or user
   * @param orgDest  organization or user
   * @returns true if success
   */
  public abstract createFork(login: string, repoOri: string, orgOri: string, orgDest: string): Promise<boolean>;

  /**
   * rename repository , use after a temporary repository is created
   * @param owner organization or user
   * @param repo repository name
   * @param newName new name for repository
   * @returns true if success
   */
  public abstract renameRepository(owner: string, repo: string, newName: string): Promise<boolean>;

  /**
   * create file in repository, if file exists, update the content
   * instead of save, this method create without commit , and without verification
   * @param owner organization or user
   * @param repo repository name
   * @param path ex '/folder1/tsconfig.json'
   * @param content string or Uint8Array for binary files
   * @returns true if success
   */
  public abstract createFileInRepo(owner: string, repo: string, path: string, content: string | Uint8Array): Promise<boolean>;


  /**
   * change visibility of repository
   * @param owner organization or user
   * @param repo repository name
   * @param visibility 'PUBLIC', 'PRIVATE' or 'INTERNAL'
   */
  public abstract changeVisibility(owner: string, repo: string, visibility: 'PUBLIC' | 'PRIVATE' | 'INTERNAL'): Promise<boolean>;

  /**
   * verify if repository exists
   * return:
   *  free: free to create the repository
   *  reuse: The repository already exists for the user, you can reuse it
   *  wait: Please wait, another user is creating;
   *  error: There is a repository, but I was unable to validate the user
   */
  public abstract verifyRepositoryNew(owner: string, repo: string, user:string): Promise<
  'free' | 'reuse' | 'wait' | 'error'>;

  /**
   * verify if user has permission in repository
   * @param owner organization or user
   * @param repo repository name
   * @param login login name, get from getUserInfo method
   */
  public abstract verifyPermission(owner: string, repo: string, login: string): Promise<IPermission>;

  /**
   * add variable to repository, if exists, update the value
   * use variable to store sensitive information, like secrets do collab backend
   * @param name variable name
   * @param value variable value
   * @returns true if success
   */
  public abstract addVariable(name: string, value: string): Promise<boolean>;

  /**
   * update variable value
   * @param name variable name
   * @param value variable value
   * @returns true if success
   */
  public abstract updateVariable(name: string, value: string): Promise<boolean>;

  /**
   * list variables of repository
   * @returns list of variables
   */
  public abstract listVariables(): Promise<{ variables: { name: string, value: string, created_at: string, updated_at: string }[], total_count: number }>;

  /**
   * delete variable of repository
   * @param name variable name
   * @returns true
   */
  public abstract delVariable(name: string): Promise<boolean>;

}


export interface IDriverKey {
   project: number;
  shortName: string;
   driverVersion: string;
}


const drivers: { [key: string]: DriverIOBase } = {};

/**
 * find and return instance of DriverIOBase
 */
export const getDriver = (provider: mls.cbe.Provider): DriverIOBase | undefined => {
  return drivers[provider];
}


/**
 * find and return instance of DriverIOBase
 * find in project or project base (in project dependencies)
 */
export const getDefaultDriver = (project: number): DriverIOBase => {
  const driverName = mls.l5.getProjectSettings(project)?.projectDriver || "mls";
  let provider: mls.cbe.Provider;
  if (driverName === "GitHub") provider = "github";
  else if (driverName === "GitLab") provider = "gitlab";
  else throw new Error(`Driver _${project}_${driverName} not found`);
  let driver = getDriver(provider);
  if (!driver) {
    project = mls.l5.getBaseProject(project);
    driver = getDriver(provider);
  }
  if (!driver) throw new Error(`Driver _${project}_${driverName} not found`);
  return driver;
}

/**
 * get list of drivers in imemory
 */
export const getDriversInfo = (): IDriverKey[] => {
  const list: IDriverKey[] = [];
  const keys = Object.keys(drivers);
  for (const key of keys) {
    const driver = drivers[key];
    list.push({
      project: driver.project,
      shortName: driver.shortName,
      driverVersion: driver.driverVersion
    });
  }
  return list;
}

export const addDriver = (driver: DriverIOBase, provider: mls.cbe.Provider) => {
  if (!driver ||
    !driver.shortName ||
    driver.project < 0 ||
    !driver.driverVersion) throw new Error('Invalid driver');
  drivers[provider] = driver;
};

export const removeDriver = (driverName: string) => {
  delete drivers[driverName];
};

/**
 * @internal
 */
export const getContents = async (project: number, fileInfos: mls.stor.IFileInfo[]): Promise<mls.stor.IRegGetContents[]> => {
  const driver = getDefaultDriver(project);
  return driver.getContents(project, fileInfos);
};

/**
 * @internal
 */
export const setContents = async (project: number, fileInfos: mls.stor.IFileInfo[], comments: string | null): Promise<boolean> => {
  const driver = getDefaultDriver(project);
  const isOk = await driver.setContents(project, fileInfos, comments);
  if (isOk) {
    fileInfos.forEach((fileInfo) => {
      if (!fileInfo.inLocalStorage) return;
      // clear localstor
      mls.stor.localStor.setContent(fileInfo, { content: null });
      fileInfo.inLocalStorage = false;
    })
  }
  return isOk;
};

/**
 * @internal
 */
export const getHistory = async (project: number, fileInfo: mls.stor.IFileInfo): Promise<IHistory[] | null> => {
  const driver = getDefaultDriver(project);
  return driver.getHistory(fileInfo);
};

/**
 * @internal
 */
export const getHistoryContent = async (project: number, fileInfo: mls.stor.IFileInfo, ref: string): Promise<string | null> => {
  const driver = getDefaultDriver(project);
  return driver.getHistoryContent(fileInfo, ref);
};

export interface IInfo {
  name: string,
  login: string,
  avatarUrl: string
}

export declare interface IOrg {
  name: string,
  id: string,
  avatarUrl: string,
  visibility: string
}


export interface IPullRequest {
  id: string,
  title: string,
  url: string,
  body: string,
  state: 'open' | 'closed' | 'merged' | 'other',
  mergedAt: string,
  closedAt: string,
  createdAt: string,
  author: {
    login: string
  }
}

export interface IFork {
  nameWithOwner: string,
  name: string,
  owner: { login: string },
  defaultBranchRef: { name: string },
  createdAt: string
}

export interface IBranch {
  name: string
}

export interface IPermission {
  write: boolean,
  read: boolean,
  create: boolean,
  delete: boolean,
}

