import { ProjectsLastModified } from "@common/global.cbe.types";
import { mls } from "../../src/index";
import { IFileInfo } from "./stor";

interface IIndexedDBFile {
  key: string;
  fileInfo: mls.stor.IFileInfoPersistent;
  info: mls.stor.IFileInfoValue;
}

export interface IIndexedDBPrj {
  key: string;
  project: number;
  repository_lastModified?: string;
  fileInfo: mls.cbe.IPrjSourcesFiles[];
  importsMap: string;
  indexModules: string;

}

const filePrefix = 'File_';
const PrjPrefix = 'Prj_';
const TaskPrefix = 'Task_';

const getKeyToFile = (project: number, level: number, shortName: string, folder: string, extension: string): string => {
  if (folder) return `${filePrefix}${project}_${level}_${folder.replace(/\//g, '_')}_${shortName}_${extension}`;
  return `${filePrefix}${project}_${level}_${shortName}_${extension}`;
};

export const parseKeyToFile = (key: string): { project: number, level: number, shortName: string, folder: string, extension: string } => {
  if (!key.startsWith(filePrefix)) return { project: 0, level: 0, shortName: "", folder: "", extension: "" };
  key = key.substring(filePrefix.length);
  const ar: string[] = key.split("_"); // ex key 100111_3_folder1_folder2_test1_.txt
  const folder: string = ar.length > 4 ? ar.slice(2, -2).join("/") : "";
  const shortName = ar[ar.length - 2];
  const extension = ar[ar.length - 1];
  const [project, level] = ar;
  return { project: Number(project), level: Number(level), shortName, folder, extension };
}

export const parseKeyToProject = (key: string): number => {
  if (!key.startsWith(PrjPrefix)) return 0;
  key = key.substring(PrjPrefix.length);
  const project = Number(key);
  return project < 1 ? 0 : project;
};

export const getKeyToPrj = (project: number) => {
  return `${PrjPrefix}${project}`;
}

export const getKeyToTask = (project: number, task: number) => {
  return `${TaskPrefix}${project}_${task}`;
}

export const getPrefixTasks = (project: number) => {
  return `${TaskPrefix}${project}_`;
}

/**
 * @internal
 */
export const getPrefixToLocalStorageWithProject = (project: number): string => {
  return `${filePrefix}${project}_`;
}

/**
 * @internal
 */
export const getPrefixToLocalStorage = (): string => {
  return filePrefix;
}

/**
 * @internal
 */
export const getInfoFromLocalStorage = async (key: string): Promise<IIndexedDBFile | null> => {
  if (!key.startsWith(filePrefix)) return null;
  key = key.substring(filePrefix.length);
  const ar: string[] = key.split("_"); // ex key 100111_3_folder1_folder2_test1_.txt
  const folder: string = ar.length > 4 ? ar.slice(2, -2).join("/") : "";
  const shortName = ar[ar.length - 2];
  const extension = ar[ar.length - 1];
  const [project, level] = ar;
  const result = await readFile({ project: Number(project), level: Number(level), shortName, folder, extension })
  .catch(() => null);
  return result;
  // return { project: Number(project), level: Number(level), shortName, folder, extension };
}

const dbName = "mlsDB";
const tbName = "tempObjects";
const version = 1;

const openDatabase = async (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(dbName, version);

    request.onupgradeneeded = (event: IDBVersionChangeEvent) => {
      const db = (event.target as IDBOpenDBRequest).result;
      db.createObjectStore(tbName, { keyPath: "key" });
    };

    request.onsuccess = (event: Event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBOpenDBRequest).error);
    };
  });
};

/**
 * Saves an object in IndexedDB using the given key.
 * @param object - The object to store, containing both key and data.
 * @returns A Promise that resolves when the object is successfully saved.
 * @example
 * ```
 * const myJson: IIndexedDBObject = {
 *   key: "myKey",
 *   data: {
 *     name: "John",
 *     age: 30,
 *     city: "New York",
 *   },
 * };
 *
 * saveObject(myJson)
 *   .then(() => console.log("Object saved successfully!"))
 *   .catch((error) => console.error("Error saving object:", error));
 * ```
 */
const saveObject = async (object: IIndexedDBFile | IIndexedDBPrj): Promise<void> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readwrite");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.put(object);

    transaction.oncomplete = () => {
      resolve();
    };

    transaction.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
};

export const saveFile = async (fileInfo: mls.stor.IFileInfo, info: mls.stor.IFileInfoValue): Promise<void> => {
  const { project, level, shortName, folder, extension, versionRef, isLocalVersionOutdated, status, inLocalStorage, hasError, updatedAt } = fileInfo;
  if (!info.content) throw new Error("No content to save in IndexedDB");
  const key = getKeyToFile(project, level, shortName, folder, extension);
  const obj: IIndexedDBFile = {
    key,
    fileInfo: { project, level, shortName, folder, extension, versionRef, isLocalVersionOutdated, status, inLocalStorage, hasError, updatedAt, projectDependencies: null },
    info,
  };
  return saveObject(obj);
}

/**
 * Saves project information to local database.
 * @param project - The project number.
 * @param info - An array of project files.
 * @param baseProject_lastModified - The last modified date of the base project.
 * @returns A promise that resolves when the project information is saved.
 */
export const savePrjInfo = async (project: number, info: mls.cbe.IPrjSourcesInfo, baseProject_lastModified: string): Promise<void> => {
  if (project < 1) throw new Error("Invalid project information to save in IndexedDB, invalid project number");
  if (isNaN(new Date(baseProject_lastModified).getTime())) {
    throw new Error(`Invalid project information to save in IndexedDB, invalid last modified date:${baseProject_lastModified}`);
  }
  if (!info || !info.filesInfo || info.filesInfo.length < 1) {
    throw new Error(`Invalid project information to save in IndexedDB, file length:${info?.filesInfo?.length}`);
  }
  const key = getKeyToPrj(project);
  const obj: IIndexedDBPrj = {
    key,
    project,
    fileInfo: info.filesInfo,
    importsMap: info.importsMap,
    indexModules: info.indexModules,
    repository_lastModified: baseProject_lastModified,
  };
  return saveObject(obj);
}

/**
 * Removes project information from the local database.
 * use to refresh projects information on next load
 *
 * @param project - The project number.
 * @returns A promise that resolves when the project information is successfully removed.
 */
export const removePrjInfo = async (project: number): Promise<void> => {
  return removeKey(getKeyToPrj(project));
}

  /**
   * Reads an object from IndexedDB using the given key.
   * @param key - The key used to retrieve the object.
   * @returns A Promise that resolves with the object when successfully read.
   * @example
   * ```
   * readObject("myKey")
   *   .then((object) => console.log("Object value:", object))
   *   .catch((error) => console.error("Error reading object:", error));
   * ```
   */
const readObject = async (key: string): Promise<IIndexedDBFile | IIndexedDBPrj> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readonly");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.get(key);

    request.onsuccess = (event: Event) => {
      const file: IIndexedDBFile = (event.target as IDBRequest).result;
      if (!file) return reject(new Error(`Object not found in IndexedDB, key: ${key} event:${JSON.stringify(event)}`));
      if (!file.info) file.info = { content: null }
      resolve(file);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
};

export const readFile = async ({ project, level, shortName, extension, folder }:
  {project: number, level: number, shortName: string, extension: string, folder: string})
: Promise<IIndexedDBFile> => {
  // return object or abend
  return readObject(getKeyToFile(project, level, shortName, folder, extension)) as unknown as IIndexedDBFile;
}

export const readPrjInfo = async (project: number): Promise<IIndexedDBPrj> => {
  // return object or abend
  const rc = await readObject(getKeyToPrj(project)) as unknown as IIndexedDBPrj;
  if (rc.fileInfo) return rc;
  throw new Error("Project info not found in IndexedDB");
}

/**
 * get content from multilevel studio - backend server
 * @internal
 */

export async function getContentInfoOrNull(this: IFileInfo): Promise<mls.stor.IFileInfoValue> {
  if (!this.inLocalStorage) return { content: null };
  const file = await readFile({
    project: this.project,
    level: this.level,
    shortName: this.shortName,
    extension: this.extension,
    folder: this.folder,
  });
  return file.info;
}

/**
 * Clears the storage for the specified key in IndexedDB.
 * @param key - The key of the object to be removed from storage.
 * @returns A Promise that resolves when the storage is successfully cleared for the specified key.
 * @example
 * ```
 * removeItem("myKey")
 *   .then(() => console.log("Storage cleared for the specified key!"))
 *   .catch((error) => console.error("Error clearing storage for the specified key:", error));
 * ```
 */
export const removeItem = async (fileInfo: mls.stor.IFileInfo): Promise<void> => {
  const { project, level, shortName, folder, extension } = fileInfo;
  const key = getKeyToFile(project, level, shortName, folder, extension);
  return removeKey(key);
};

export const removeKey = async (key: string): Promise<void> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readwrite");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.delete(key);

    transaction.oncomplete = () => {
      resolve();
    };

    transaction.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
}

  /**
   * Clears all storage in IndexedDB.
   * @returns A Promise that resolves when the storage is successfully cleared for all keys.
   * @example
   * ```
   * clearAllItems()
   *   .then(() => console.log("All storage cleared!"))
   *   .catch((error) => console.error("Error clearing all storage:", error));
   * ```
   */
export const clearAllItems = async (): Promise<void> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readwrite");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.clear();

    transaction.oncomplete = () => {
      resolve();
    };

    transaction.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
};

/**
 * Retrieves all keys in IndexedDB that start with the specified prefix.
 * @param prefix - The prefix used to filter the keys.
 * @returns A Promise that resolves with an array of keys that start with the specified prefix.
 * @example
 * ```
 * getKeysWithPrefix("user")
 *   .then((keys) => console.log("Keys with prefix:", keys))
 *   .catch((error) => console.error("Error retrieving keys with prefix:", error));
 * ```
 */
export const getKeysWithPrefix = async (prefix: string): Promise<string[]> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readonly");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.openCursor();
    const keys: string[] = [];

    request.onsuccess = (event: Event) => {
      const cursor = (event.target as IDBRequest).result as IDBCursorWithValue;

      if (cursor) {
        if (cursor.key.toString().startsWith(prefix)) {
          keys.push(cursor.key.toString());
        }
        cursor.continue();
      } else {
        resolve(keys);
      }
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
};

/**
 * Retrieves all keys in IndexedDB.
 * @returns A Promise that resolves with an array of all keys in IndexedDB.
 * @example
 * ```
 * getAllKeys()
 *   .then((keys) => console.log("All keys:", keys))
 *   .catch((error) => console.error("Error retrieving all keys:", error));
 * ```
 */
export const getAllKeys = async (): Promise<string[]> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readonly");
    const objectStore: IDBObjectStore = transaction.objectStore(tbName);
    const request = objectStore.getAllKeys();
    const keys: string[] = [];

    request.onsuccess = (event: Event) => {
      resolve((event.target as IDBRequest).result);
    };

    request.onerror = (event: Event) => {
      reject((event.target as IDBRequest).error);
    };
  });
};

/**
 * read IndexedDB , and return all projects with files with local changes
 */
export const getAllProjects = async (): Promise<number[]> => {
  const keys = await getKeysWithPrefix(filePrefix);
  const projects: number[] = [];
  keys.forEach((key) => {
    const { project } = parseKeyToFile(key);
    if (!projects.includes(project)) projects.push(project);
  });
  return projects;
}

/**
 * Read IndexedDB and return [ { projectId, lastModified }]
 */
export const getProjectsLastModified = async (): Promise<ProjectsLastModified[]> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readonly");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.openCursor();
    const projects: ProjectsLastModified[] = [];

    request.onsuccess = (event: Event) => {
      const cursor = (event.target as IDBRequest).result as IDBCursorWithValue;

      if (cursor) {
        const key = cursor.key.toString();
        if (key.startsWith(PrjPrefix)) {
          const project = parseKeyToProject(key);
          const repository_lastModified = cursor.value.repository_lastModified || "";
          if (project && repository_lastModified) {
            projects.push({ project, lastModified: repository_lastModified });
          }
        }
        cursor.continue();
      } else {
        resolve(projects);
      }
    };

    request.onerror = (event: Event) => {
      console.error("Error retrieving projects last modified:", (event.target as IDBRequest).error);
      resolve([]);
    };
  });
}

/**
 * Checks if a key exists in IndexedDB.
 * @param key - The key to check for existence.
 * @returns A Promise that resolves with a boolean indicating whether the key exists in IndexedDB.
 * @example
 * ```
 * exists("myKey")
 *   .then((exists) => console.log("Key exists:", exists))
 *   .catch((error) => console.error("Error checking key existence:", error));
 * ```
 */
export const exists = async (key: string): Promise<boolean> => {
  const db = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(tbName, "readonly");
    const objectStore = transaction.objectStore(tbName);
    const request = objectStore.getKey(key);

    request.onsuccess = (event: Event) => {
      resolve((event.target as IDBRequest).result !== undefined);
    };

    request.onerror = (event: Event) => {
      resolve(false);
      // reject((event.target as IDBRequest).error);
    };
  });
};

/**
 * Checks if a file exists in IndexedDB.
 * @returns A Promise that resolves with a boolean indicating whether the key exists in IndexedDB.
 */
export const existFile = async ({ project, level, shortName, extension, folder }:
  {project: number, level: number, shortName: string, extension: string, folder: string})
: Promise<boolean> => {
  return exists(getKeyToFile(project, level, shortName, folder, extension));
}
