const getUriL1OrL2 = (storFile: mls.stor.IFileInfo): monaco.Uri => {
  let uri: monaco.Uri;
  if (storFile.level === 1) {
    // | _project_
    // | | l1
    // | | | folder
    // | | | | file.ts
    uri = monaco.Uri.parse(`file://server/_${storFile.project}_/l1/${storFile.folder ? storFile.folder + '/' : ''}${storFile.shortName}${storFile.extension}`);
  } else {
    // uri = monaco.Uri.parse(`file://server/_${storFile.project}_${storFile.folder ? storFile.folder + '_' : ''}${storFile.shortName}${storFile.extension}`);
    uri = monaco.Uri.parse(`file://server/_${storFile.project}_/l2/${storFile.folder ? storFile.folder + '/' : ''}${storFile.shortName}${storFile.extension}`);
  }
  return uri;
}

export const createModelTS = async (storFile: mls.stor.IFileInfo, content: string): Promise<IModelTS> => {
  if (!storFile || storFile.extension !== '.ts') throw new Error('invalid storFile, use a valid ts file');
  const uri: monaco.Uri = getUriL1OrL2(storFile);
  const model = monaco.editor.getModel(uri);
  if (model) throw new Error(`model already exists, uri: ${uri.toString()}`);
  const result: IModelTS = {
    model: monaco.editor.createModel(content || '', 'typescript', uri),
    storFile,
    codeLens: {},
    compilerResults: undefined,
  }
  await registerModelsEntry(storFile, result, undefined, undefined, undefined, undefined);
  return result;
}

