export const createModelProjectDefinition = async (project: number, content: string): Promise<IModelTS> => {
  if (!content) throw new Error('invalid content');
  if (project < 1 || !mls.stor.projects[project]) throw new Error('invalid project');
  const uri = monaco.Uri.parse(`file://server/_${project}_.d.ts`);
  const model = monaco.editor.getModel(uri);
  if (model) throw new Error(`model defintion already exists, uri: ${uri.toString()}`);
  const result: IModelTS | any = {
    model: monaco.editor.createModel(content || '', 'typescript', uri),
    storFile: undefined, // no storFile
    codeLens: {},
    compilerResults: undefined,
  }
  const key = `_${project}_`;
  models[key] = { ts: result };
  return result;
}

