export const getKeyModel = (project: number, shortName: string, folder: string, level: number): string => {
  if (folder) return `_${project}_${level === 1 ? level.toString() + "_" : ""}${folder}_${shortName}`;
  return `_${project}_${level === 1 ? level.toString() + "_" : ""}${shortName}`;
}

/**
 * load all files from ShortName, and create models in memory
 */
export const addModels = async (project: number, shortName: string, folder: string, level: number): Promise< mls.editor.IModels | undefined >=> {
  const files = await mls.stor.getFiles({ project, shortName, folder, loadContent: true, level });
  if (files.ts) await createModelTS(files.ts, files.tsContent || '');
  if (files.test) await createModelTest(files.test, files.testContent || '');
  if (files.defs) await createModelDefs(files.defs, files.defsContent || '');
  if (files.html) await createModelHTML(files.html, files.htmlContent || '');
  if (files.less) await createModelStyle(files.less, files.lessContent || '');
  return getModels(project, shortName, folder, level);
}

/**
 * load one file and create models in memory
 */
export const addModel = async (file: mls.stor.IFileInfoBase, content: string): Promise<mls.editor.IModelBase | undefined> => {
  if (file.extension === '.ts') return await createModelTS(file as mls.stor.IFileInfo, content);
  if (file.extension === '.test.ts') return await createModelTest(file as mls.stor.IFileInfo, content);
  if (file.extension === '.defs.ts') return await createModelDefs(file as mls.stor.IFileInfo, content);
  if (file.extension === '.html') return await createModelHTML(file as mls.stor.IFileInfo, content);
  if (file.extension === '.less') return await createModelStyle(file as mls.stor.IFileInfo, content);
  return undefined;
}

const registerModelsEntry = async (storFile: mls.stor.IFileInfo, tsModel: IModelTS | undefined, html: IModelHTML | undefined, style: IModelTS | undefined, test: IModelTest | undefined, defs: IModelDefs | undefined) => {
  const key = getKeyModel(storFile.project, storFile.shortName, storFile.folder, storFile.level);
  let modelCreated = false;
  if (models[key]) {
    if ((tsModel && !models[key].ts) ||
      (html && !models[key].html) ||
      (style && !models[key].style) ||
      (test && !models[key].test) ||
      (defs && !models[key].defs)
    ) modelCreated = true;
    if (tsModel)models[key].ts = tsModel;
    if (test) models[key].test = test;
    if (defs) models[key].defs = defs;
    if (html) models[key].html = html;
    if (style) models[key].style = style;

  } else {
    models[key] = { ts: tsModel, html, style, test, defs };
    modelCreated = true;
  }
  if (modelCreated) {
    const time = 0;
    await mls.events.fire(storFile.level as mls.Level, 'MonacoModelCreated', mls.stor.convertFileToFileReference(storFile), time)
  }
}

/**
 * delete model from memory and optionally release monaco model
 */
export const deleteModels = (project: number, shortName: string, folder: string, releaseMonacoModel: boolean, level: number): boolean => {
  const keyToModel = getKeyModel(project, shortName, folder, level);
  if (!models[keyToModel]) return false;
  if (releaseMonacoModel) {
    if (models[keyToModel].ts) models[keyToModel].ts?.model.dispose();
    if (models[keyToModel].html) models[keyToModel].html?.model.dispose();
    if (models[keyToModel].style) models[keyToModel].style?.model.dispose();
    if (models[keyToModel].test) models[keyToModel].test?.model.dispose();
    if (models[keyToModel].defs) models[keyToModel].defs?.model.dispose();
  }
  delete models[keyToModel];
  return true;
}

/**
 *  get model from memory
 */
export const getModels = (project: number, shortName: string, folder: string, level: number = 2): mls.editor.IModels | undefined => {
  return mls.editor.models[getKeyModel(project, shortName, folder, level)];
}

export const getModel = (storFile: mls.stor.IFileInfoBase): mls.editor.IModelBase | undefined => {
  const keyToModel = getKeyModel(storFile.project, storFile.shortName, storFile.folder || '', storFile.level || 2);
  const myModels = mls.editor.models[keyToModel];
  if (!myModels) return undefined;
  switch (storFile.extension) {
    case '.ts': return myModels.ts;
    case '.test.ts': return myModels.test;
    case '.defs.ts': return myModels.defs;
    case '.html': return myModels.html;
    case '.less': return myModels.style;
  }
  return undefined;
}

export const getModelById = (modelId: string): mls.editor.IModelHTML | mls.editor.IModelStyle | mls.editor.IModelTS | mls.editor.IModelDefs| undefined =>{
  for (const key of Object.keys(mls.editor.models)) {
    const _models = mls.editor.models[key];
    for (const modelType of Object.keys(_models) as Array<'ts' | 'html' | 'style' | 'test' | 'defs'>) {
      const modelEntry = _models[modelType];
      if (modelEntry && modelEntry.model?.id === modelId) {
        return modelEntry;
      }
    }
  }
  return undefined;
}

