/**
 * instances of monaco editor, ex mls.editor.instances.l2_left. xxxx
 */
export const instances: { [label: string]: monaco.editor.IStandaloneCodeEditor } = {};

export let activeInstance: '' | 'l2_left' | 'l2_right' = '';

export const setActiveInstance = (level: number, position: 'left' | 'right') => {
  if (level !== 1 && level !== 2) return;
  activeInstance = `l${level}_${position}` as 'l2_left' | 'l2_right';
}

/**
 * get level and position from active editor
 */
export const getInfoFromActiveInstance = (): { level: number, position: 'left' | 'right' } => {
  const level = Number(activeInstance.substring(1, 2));
  const position: 'left' | 'right' = activeInstance.substring(3) as 'left' | 'right';
  return { level, position };
}

/**
 * return 'left' or 'right', from side of editor, default='left'
 */
export const findPositionOfEditor = (editor: monaco.editor.ICodeEditor): 'left' | 'right' => {
  if (!editor || editor.getId() === instances.l2_left?.getId()) return 'left';
  return 'right';
}

/**
 * find all editors with model1 attached
 */
export const findEditorsByModel = (model: monaco.editor.ITextModel): monaco.editor.ICodeEditor[] => {
  const list: monaco.editor.ICodeEditor[] = [];
  if (!model || !model.isAttachedToEditor()) return list;
  monaco.editor.getEditors().forEach((editor) => {
    if (editor.getModel()?.id === model.id) list.push(editor);
  });
  return list;
};


/**
 * Init monaco
 * exec only on first call
 */
let onFirstInitMonaco = true;
export const InitMonaco = async (): Promise<void> => {

  if (!onFirstInitMonaco) return;
  onFirstInitMonaco = false;

  // avoid restart worker problems
  // ref: https://github.com/microsoft/monaco-editor/issues/461#issuecomment-420858239
  monaco.languages.typescript.typescriptDefaults.setEagerModelSync(true);
  monaco.languages.typescript.typescriptDefaults.setMaximumWorkerIdleTime(30 * 1000);
  setTypescriptConfig();
  setTypescriptExtraLibs();
  mls.l2.typescript.enableMlsTSWorkerIfNeeded();
  mls.l2.codeLens.initCodeLens();
}

