const flattenDiagnosticMessageText = (
  diag: string | ts.DiagnosticMessageChain | undefined,
  newLine: string,
  indent = 0
  ): string => {
  if (typeof diag === 'string') {
    return diag;
  } else if (diag === undefined) {
    return '';
  }
  let result = '';
  if (indent) {
    result += newLine;

    for (let i = 0; i < indent; i++) {
      result += '  ';
    }
  }
  result += diag.messageText;
  indent++;
  if (diag.next) {
    for (const kid of diag.next) {
      result += flattenDiagnosticMessageText(kid, newLine, indent);
    }
  }
  return result;
};

export const convertTypescriptPosToMonacoRange = (model: monaco.editor.ITextModel, diagStart?: number, diagLength?: number): monaco.Range => {
  diagStart = diagStart || 0;
  diagLength = diagLength || 1;
  const { lineNumber: startLineNumber, column: startColumn } = model.getPositionAt(diagStart);
  const { lineNumber: endLineNumber, column: endColumn } = model.getPositionAt(diagStart + diagLength);
  return new monaco.Range(startLineNumber, startColumn, endLineNumber, endColumn);
}

/**
 * replace or add markers
 * @param addMarkers default false, if true, add markers, if false, replace markers
 */
export const showModelDecorations = (model: monaco.editor.ITextModel, diags: monaco.languages.typescript.Diagnostic[], addMarkers: boolean = false): void => {

  function _tsDiagnosticCategoryToMarkerSeverity(category: number): monaco.MarkerSeverity {
    switch (category) {
      case 1: return monaco.MarkerSeverity.Error;
      case 3: return monaco.MarkerSeverity.Info;
      case 0: return monaco.MarkerSeverity.Warning;
      case 2: return monaco.MarkerSeverity.Hint;
    }
    return monaco.MarkerSeverity.Info;
  }

  function _convertDiagnostics(diag: monaco.languages.typescript.Diagnostic): monaco.editor.IMarkerData {
    const { startLineNumber, startColumn, endLineNumber, endColumn } = convertTypescriptPosToMonacoRange(model, diag.start, diag.length);
    const tags = [];
    if (diag.reportsUnnecessary) {
      tags.push(monaco.MarkerTag.Unnecessary);
    }
    if (diag.reportsDeprecated) {
      tags.push(monaco.MarkerTag.Deprecated);
    }
    return {
      severity: _tsDiagnosticCategoryToMarkerSeverity(diag.category),
      startLineNumber,
      startColumn,
      endLineNumber,
      endColumn,
      message: flattenDiagnosticMessageText(diag.messageText, "\n"),
      code: diag.code.toString(),
      tags,
    };
  }

  let markers: monaco.editor.IMarkerData[] = [];
  if (addMarkers) {
    markers = monaco.editor.getModelMarkers({
      resource: model.uri,
      owner: model.id,
    });
  }
  if (diags.length !== 0) markers = [...markers, ...diags.map(d => _convertDiagnostics(d))];
  monaco.editor.setModelMarkers(model, model.id, markers); // clear or set markers

};

export const addError = (model: monaco.editor.ITextModel, range: monaco.Range, msg: string): void => {
  addMarker(model, range, msg, monaco.MarkerSeverity.Error);
}

export const addInfo = (model: monaco.editor.ITextModel, range: monaco.Range, msg: string): void => {
  addMarker(model, range, msg, monaco.MarkerSeverity.Info);
}

export const addWarning = (model: monaco.editor.ITextModel, range: monaco.Range, msg: string): void => {
  addMarker(model, range, msg, monaco.MarkerSeverity.Warning);
}

export const addHint = (model: monaco.editor.ITextModel, range: monaco.Range, msg: string): void => {
  addMarker(model, range, msg, monaco.MarkerSeverity.Hint);
}

const addMarker = (model: monaco.editor.ITextModel, range: monaco.Range, msg: string, severity: monaco.MarkerSeverity): void => {
  let markers: monaco.editor.IMarkerData[] = [];
  markers = monaco.editor.getModelMarkers({
    resource: model.uri,
    owner: model.id,
  });
  // find duplicates and ignore
  for (const marker of markers) {
    if (marker.severity === severity &&
      marker.startLineNumber === range.startLineNumber &&
      marker.startColumn === range.startColumn &&
      marker.message === msg) return;
  }
  const tags: monaco.MarkerTag[] = [];
  markers.push({
    severity,
    startLineNumber: range.startLineNumber,
    startColumn: range.startColumn,
    endLineNumber: range.endLineNumber,
    endColumn: range.endColumn,
    message: msg,
    code: undefined,
    tags,
  });
  monaco.editor.setModelMarkers(model, model.id, markers);
}

/**
 * force typescript compile and show errors
 * ex, after a imported file change
 */
export const forceModelUpdate = (model: monaco.editor.ITextModel): void => {
  let range = new monaco.Range(1, 1, 1, 1);
  // model.pushEditOperations([], [{ range, text: 'a' }], () => null);
  model.applyEdits([{ range, text: 'a' }]);
  range = new monaco.Range(1, 1, 1, 2);
  // model.pushEditOperations([], [{ range, text: '' }], () => null);
  model.applyEdits([{ range, text: '' }]);
}
