import { mls } from "../index";

// Publish-Subscribe Pattern

export interface ITimeout {
  str: number;
  timeout: number;
  events: IEvents[];
}

export type Listener = (ev: IEvent) => void | Promise<void>;

export let delays: { [handle: number]: ITimeout } = {};

export let subscribers: { [key: string]: Listener[] } = {}; // key ex: 2_TSSourceChanged


