export type TypeEvent =
  | "ProjectSelected" | "ProjectChanged" | "ProjectLoaded" | "ProjectCreate" | "ProjectExplore"
  | "FileAction" | 'DomAction' | 'ProjectCompilationComplete'
  | "CSSSelectChanged"
  // widgets components
  | "WidgetAction"
  | 'PluginDetails' // show plugin details on service details
  // monaco editor
  | "MonacoAction"
  | "MonacoModelCreated"
  // Toolbar Events
  | "ToolBarSelected" | "ToolBarUnSelected"
  // // Design System
  // | "DSSelected"
  // // Design System - Tokens
  // | "DSTokenSelected" | "DSTokenUnSelected"
  // | "DSColorClicked" | "DSColorChanged"
  // | "DSTYPOClicked" | "DSTYPOChanged"
  // | "DSCustomClicked" | "DSCustomChanged"
  // // Design System - Documentation
  // | "DSDocSelected" | "DSDocUnSelected" | "DSDocPageClicked" | "DSDocPageChanged"
  // // Design System - Styles
  // | "DSStyleSelected" | "DSStyleUnSelected" | "DSStyleChanged" | "DSStyleCursorChanged"
  // // Design System - Icons
  // | "DSIconSelected" | "DSIconUnSelected" | "DSIconChanged"
  // // Design System - Assets
  // | "DSAssetsSelected" | "DSAssetsUnSelected" | "DSAssetsChanged"
  // // Design System - Widgets
  // | "DSWidgetsSelected" | "DSWidgetsUnSelected" | "DSWidgetsChanged";

export interface IEvents {
  levels: mls.Level[];
  types: TypeEvent[];
  desc?: string;
}

export interface IEvent {
  level: mls.Level;
  type: TypeEvent;
  desc?: string;
}

/**
 * fire a event , use Publish-Subscribe Pattern
 * @param levels ex [2,3]
 * @param types ex ['TSSourceChanged']
 * @param desc optional , use to pass parameters
 * @param timeout optional, default 200ms, use 0 to fire immediately
 */
export const fire = async (
  levels: mls.Level[] | mls.Level,
  types: TypeEvent[] | TypeEvent,
  desc?: string,
  timeout: number = 200
): Promise<void> => {
  if (!Array.isArray(levels)) levels = [levels];
  if (!Array.isArray(types)) types = [types];
  const ev: IEvents = { levels, types, desc };
  // eslint-disable-next-line no-return-await
  if (timeout <= 0) return await fireEvents([ev]); // execute now
  timeout = Math.round(timeout * 0.01) * 100; // ex: 120 -> 100 , 180 -> 200
  let delay: ITimeout | undefined = getNearTimeout(timeout);
  if (delay) {
    delay.events.push(ev);
    return;
  }
  delay = {
    str: Date.now() + timeout,
    timeout: timeout,
    events: [ev],
  };
  const handle = window.setTimeout(() => {
    fireEvents(delays[handle].events);
    if (delays[handle]) {
      delays[handle].events = []; // avoid loss memory
      delete delays[handle];
    }
  }, timeout);
  delays[handle] = delay;
}

/**
 * add subscriber , , ex mls.events.addListener(2, 'foo', onFoo)
 * @param level level from mls, ex 2
 * @param type type , ex 'TSSourceChanged'
 * @param listener Function to receive event , ex const onMyEvent = (ev: mls.events.IEvent) => void { }
 */
export const addListener = (
  level: mls.Level,
  type: TypeEvent,
  listener: Listener
): void => {
  if (!listener || typeof listener !== "function") {
    console.error(
      "Error, listener must be a function, in mls.events.addListener"
    );
    return;
  }
  if (typeof level !== "number" || typeof type !== "string") {
    console.error(
      "Error, level must be a number and type a string, in mls.events.addListener"
    );
    return;
  }
  const key = level + "_" + type;
  if (mls.isTraceEvents) console.log("addListener key:" + key);
  const listeners = subscribers[key];
  if (listeners) {
    subscribers[key] = removeListener(subscribers[key], listener); // remove old first
    subscribers[key].push(listener);
  } else {
    subscribers[key] = [listener];
  }
}

/**
 * add subscriber , , ex addEventListener([2],['foo'], onFoo)
 * @param levels one or more levels from mls
 * @param types one or more types , ex ['TSSourceChanged']
 * @param listener Function to receive event , ex const onMyEvent = (ev: mls.events.IEvent) => void { }
 */

export const addEventListener = (
  levels: mls.Level[],
  types: TypeEvent[],
  listener: Listener
): void => {
  if (!listener || typeof listener !== "function") {
    console.error(
      "Error, listener must be a function, in mls.events.addEventListener"
    );
    return;
  }
  (levels || []).forEach((level: mls.Level) => {
    (types || []).forEach((type: TypeEvent) => {
      addListener(level, type, listener);
    });
  });
}

/**
 * remove subscriber , ex addEventListener([2,3],['foo'], onFoo); removeEventListener(undefined,undefined,onFoo)
 * to remove all from onFoo, ex removeEventListener(undefined, undefined, onFoo);
 * @param levels one or more levels from mls or undefined for remove all levels
 * @param types one or more types or undefined for remove all types
 * @param listener Function to receive event , ex const onMyEvent = (ev: mls.events.IEvent) => void { }
 */

export const removeEventListener = (
  levels: mls.Level[] | undefined,
  types: TypeEvent[] | undefined,
  listener: Listener
): void => {
  if (!listener || typeof listener !== "function") return;
  (levels || [1, 2, 3, 4, 5, 6, 7]).forEach((level: number) => {
    if (!types) {
      // remove all
      const keys: string[] = Object.keys(subscribers);
      for (let i = 0; i < keys.length; i++) {
        const key = keys[i];
        if (key.startsWith(level + "_")) {
          subscribers[key] = removeListener(subscribers[key], listener);
        }
      }
    }
    (types || []).forEach((type: string) => {
      const key = level + "_" + type;
      const listeners = subscribers[key];
      if (listeners) {
        subscribers[key] = removeListener(subscribers[key], listener);
      }
    });
  });
}

const removeListener = (listeners: Listener[], listener: Listener): Listener[] => {
  if (!listeners) return [];
  // const comp = listener.toString();
  for (let i = listeners.length - 1; i >= 0; i--) {
    // compare objects with === , not with indexof
    if (Object.is(listeners[i], listener)) {
      listeners.splice(i, 1);
    }
    // if (listeners[i].toString() === comp) listeners.splice(i, 1);
  }
  return listeners;
}

const fireEvents = async (evs: IEvents[]): Promise<void> => {
  // search for Subscribes
  const duplicates: string[] = [];
  for await (const ev of evs || []) {
    for await (const level of ev.levels || []) {
      for await (const type of ev.types || []) {
        const key = level + "_" + type;
        const listeners = subscribers[key];
        if (!listeners || typeof level !== "number" || typeof type !== "string") return;
        const pes = key + "_" + ev.desc;
        if (duplicates.indexOf(pes) >= 0) return; // avoid duplicates
        duplicates.push(pes);
        for await (const listener of listeners) {
          const rc: any = await fireOneEvent({ level, type, desc: ev.desc }, listener);
          if (!rc) removeEventListener([level], [type], listener); // avoid loop of errors
        }
      }
    }
  }
}

const fireOneEvent = async (ev: IEvent, listener: Listener): Promise<boolean> => {
  if (!listener || typeof listener !== "function") return false;
  if (mls.isTraceEvents) console.time('fireOneEvent_key_' + ev.level + '_' + ev.type + '_' + ev.desc?.substring(0, 20));
  let rc = listener(ev);
  if (typeof rc?.then === 'function') {
    try {
      rc = await rc; // wait for complete
    } catch (e) {
      if (mls.isTraceEvents) console.timeEnd('fireOneEvent_key_' + ev.level + '_' + ev.type + '_' + ev.desc?.substring(0, 20));
      console.log("error on fire event: level:" + ev.level + ", type:" + ev.type + ", desc:" + ev.desc || Number(", function: ") + ((rc as any).name as string || "?"));
      console.error("trace: ", e);
      return false;
    }
  }
  if (mls.isTraceEvents) console.timeEnd('fireOneEvent_key_' + ev.level + '_' + ev.type + '_' + ev.desc?.substring(0, 20));
  return true;
}

const getNearTimeout = (timeout: number): ITimeout | undefined =>{
  const str = Date.now() + timeout;
  const keys: string[] = Object.keys(delays);
  for (let i = 0; i < keys.length; i++) {
    const key = Number(keys[i]);
    if (Math.abs(delays[key] && delays[key].str - str) < 100) return delays[key];
  }
  return undefined;
}

/**
 * fire a specific action
 * @param newProject optional for rename
 * @param newshortName optional for rename
 * @param newfolder optional for rename
 * @param newEnhancement optional for rename
 */
export const fireFileAction = async (action: mls.events.FileActions,
storFile: mls.stor.IFileInfo,
position: 'left' | 'right',
newProject?: number,
newshortName?: string,
newfolder?: string,
newEnhancement?: string,
timeout: number = 200): Promise<void> => {
  const args: mls.events.IFileAction = {
    action,
    level: storFile.level,
    position,
    project: storFile.project,
    shortName: storFile.shortName,
    folder: storFile.folder,
    extension: storFile.extension,
    newProject,
    newshortName,
    newfolder,
    newEnhancement
  };
  return mls.events.fire(storFile.level as mls.Level,
    'FileAction',
    JSON.stringify(args),
    timeout);
}

/**
 * fire a Monaco action, example, after a codeLen link
 */
export const fireMonacoAction = async (
  action: 'gotoPosition' | 'helpAssistant',
  storFile: mls.stor.IFileInfo,
  codeLenCommand: mls.l2.codeLens.ICodeLenCommand | undefined,
  position: 'left' | 'right',
  filePosition: number,
  timeout: number = 200
): Promise<void> => {
  const args: mls.events.IMonacoAction = {
    action,
    level: storFile.level,
    position,
    filePosition,
    codeLenCommand,
    project: storFile.project,
    shortName: storFile.shortName,
    folder: storFile.folder,
    extension: storFile.extension,
  };
  return mls.events.fire(storFile.level as mls.Level,
      'MonacoAction',
      JSON.stringify(args),
      timeout);
}


