/**
 * Initialize Firebase app and messaging
 */
const initializeFirebase = (): any => {
  if (!window.firebase) {
    throw new Error('Firebase not loaded. Make sure mlsLib.min.js is loaded first.');
  }

  // Initialize Firebase app if not already initialized
  if (!window.firebase.apps.length) {
    window.firebase.initializeApp(firebaseConfig.firebase);
  }

  return window.firebase.messaging();
};

/**
 * Get Firebase Cloud Messaging token for backend registration
 * @returns Promise<string | null> - FCM token or null if failed
 */
export const getFCMTokenForBackend = async (): Promise<string | null> => {
  try {
    const reg = await mls.stor.cache.installIfNeeded();
    if (!reg) throw new Error("Service Worker not available");
    if (Notification.permission !== 'granted') {
      const perm = await Notification.requestPermission();
      if (perm !== 'granted') return null;
    }

    const { initializeApp } = await import('firebase/app');
    const { getMessaging, getToken } = await import('firebase/messaging');

    const app = initializeApp(firebaseConfig.firebase);
    const messaging = getMessaging(app);

    // IMPORTANT: pass your own ServiceWorkerRegistration
    const token = await getToken(messaging, {
      vapidKey: VAPID_KEY,
      serviceWorkerRegistration: reg
    });

    return token || null;
  } catch (err) {
    console.error('Error getting FCM token:', (err as Error).message);
    return null;
  }
};

