import { mls } from "../index";

// routines and functions to LESS and CSS

export interface IStyleResult {
    errors: monaco.languages.typescript.Diagnostic[];
    css: string;
    trace: string[];
    modelVersion: number;
    compiledVersion: number, // if same with modelVersion, don't need to recompile
    tripleSlashMLS?: mls.common.tripleslash.ITripleSlash;
}


/**
 * Compiles a LESS document into CSS.
 *
 * This function takes a LESS document as a string input and compiles it to CSS.
 * If the document is empty or only whitespace, it returns an empty string.
 * Errors during compilation are caught and returned in the rejected promise.
 *
 * @param {string} doc - The LESS document to be compiled.
 * @returns {Promise<string>} A promise that resolves to the compiled CSS string.
 *
 * @example
 * compile(".myClass { color: @primaryColor; }")
 *   .then(css => console.log(css))
 *   .catch(error => console.error(error));
 */
export const compile = (doc: string, compress: boolean = false): Promise<string> => {
  return new Promise<string>((resolve, reject) => {
    if (!doc || doc.trim().length < 1) return resolve("");
    less.render(doc, { compress }).then(
            (output: Less.RenderOutput) => {
              resolve(output.css);
            },
            (error: string) => {
              reject(new Error(`Error LESS: ${error}`));
            }
        );
  });
}

/**
 * compile a model style,
 * return true if success, false if error
 * see modelStyle.styleResults for results
 */
export const compileStyle = async (modelStyle: mls.editor.IModelStyle): Promise<boolean> => {
  try {
    if (!modelStyle || !modelStyle.model || modelStyle.model.isDisposed()) throw new Error('modelStyle or model is not initialized or disposed');
    initStyleResultsIfNeed(modelStyle);
    if (!modelStyle.styleResults) throw new Error('modelStyle.styleResults is not initialized');
    if (modelStyle.styleResults.compiledVersion === modelStyle.model.getVersionId()) return true;
    modelStyle.styleResults.modelVersion = modelStyle.model.getVersionId();
    modelStyle.styleResults.compiledVersion = modelStyle.styleResults.modelVersion;
    modelStyle.styleResults.errors = [];
    modelStyle.styleResults.css = '';
    modelStyle.styleResults.trace = [];
    parseTripleSlash(modelStyle);
    const doc = modelStyle.model.getValue();
    modelStyle.styleResults.trace.push(`compileStyle, less: ${doc.length} chars`);
    const start = Date.now();
    const versionBeforeCompile = modelStyle.model.getVersionId();
    const css = await compile(doc);
    // Only assign if the version has not changed during async operation
    if (modelStyle.model.getVersionId() === versionBeforeCompile) {
      modelStyle.styleResults.css = css;
      modelStyle.styleResults.trace.push(`compileStyle css: ${modelStyle.styleResults.css.length} chars`);
      modelStyle.styleResults.trace.push(`compileStyle: ${Date.now() - start} ms`);
      return true;
    } else {
      modelStyle.styleResults.trace.push('compileStyle: model version changed during compile, skipping css assignment');
      return false;
    }
  } catch (e: Error | any) {
    addError(modelStyle, e.message || e, 0, 9999);
    return false;
  }
}

/**
 * Stores information about a file in `mls.editor.models.style`.
 * If there are errors in triple-slash references, logs the errors.
 *
 */
export const parseTripleSlash = (modelStyle: mls.editor.IModelStyle) => {
  try {
    if (!modelStyle || !modelStyle.model || modelStyle.model.isDisposed()) throw new Error('modelStyle or model is not initialized or disposed');
    const firstLine = modelStyle.model.getLinesContent()[0];
    initStyleResultsIfNeed(modelStyle);
    if (!modelStyle.styleResults) throw new Error('modelStyle.styleResults is not initialized');
    modelStyle.styleResults.tripleSlashMLS = mls.common.tripleslash.parseXMLTripleSlash(firstLine);
  } catch (e: Error | any) {
    addError(modelStyle, e.message || e, 0, 9999);
  }
}

export const addError = (modelStyle: mls.editor.IModelStyle, message: string, start: number, length: number): void => {
  initStyleResultsIfNeed(modelStyle);
  if (!modelStyle.styleResults) throw new Error(`modelStyle.styleResults is not initialized in add error${message}`);
  const error: monaco.languages.typescript.Diagnostic = {
    category: 1,
    code: 1,
    messageText: message,
    start,
    length,
    file: {
      fileName: '',
    }
  }
  modelStyle.styleResults.errors.push(error);
}

export const initStyleResultsIfNeed = (modelStyle: mls.editor.IModelStyle): void => {
  if (!modelStyle.styleResults) initCompilerResults(modelStyle);
}

export const initCompilerResults = (modelStyle: mls.editor.IModelStyle): void => {
  modelStyle.styleResults = {
    errors: [],
    css: '',
    trace: [],
    modelVersion: modelStyle.model.getVersionId(),
    compiledVersion: 0,
    tripleSlashMLS: undefined,
  };
}
