// file mls.l2.changes.ts

import { mls } from "../index";

type ChangeType = "change" | "new" | "deleted";
type ChangeOperador = "user" | "AI";

export interface ChangeGroup {
    id: string;
    type: ChangeType;
    startLine: number;
    endLine: number;
    previousContent?: string[]; /** a line content for each change, from startLine to endLine inclusive */
    currentContent?: string[];
}

export interface ModelHistory {
    changeOperador: ChangeOperador;
    changes: ChangeGroup[];
    previousContent?: string; /** full previous content  */

    addVersion(newContent: string): void;
    undo(): boolean;
    redo(): boolean;
    canUndo(): boolean;
    canRedo(): boolean;
}
