import pako from "pako";
import JSZip from "jszip";

/**
 * Compresses a JSON object, string, or Uint8Array and encodes it in base64.
 * @param data - The JSON object, string, or Uint8Array to be compressed.
 * @returns The compressed data encoded in base64.
 */
export const compressAndEncodeBase64 = (data: object | string | Uint8Array): string => {
  let inputData: Uint8Array;
  if (data instanceof Uint8Array) {
    inputData = data;
  } else if (typeof data === 'string') {
    inputData = new TextEncoder().encode(data);
  } else {
    inputData = new TextEncoder().encode(JSON.stringify(data));
  }
  const compressed: Uint8Array = pako.gzip(inputData);
  return btoa(String.fromCharCode(...compressed));
};

/**
 * Decodes a base64 string and decompresses it to retrieve the original data.
 * @param base64Data - The base64 encoded compressed string.
 * @returns The original JSON object, string, or Uint8Array.
 */
export const decodeAndDecompressBase64 = (base64Data: string): string | object => {
  const compressedData = new Uint8Array(atob(base64Data).split("").map(c => c.charCodeAt(0)));
  const decompressedData = pako.ungzip(compressedData);
  const resultString = new TextDecoder('utf-8').decode(decompressedData);
  try {
    return JSON.parse(resultString) as Object;
  } catch {
    return resultString;
  }
};

export const base64ToArrayBuffer = (base64: string): ArrayBuffer => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}

export const unzipBase64 = async (base64: string): Promise<{ key: string, value: string }[]> => {
  const arrayBuffer: ArrayBuffer = base64ToArrayBuffer(base64);
  const ret: { key: string, value: string }[] = [];
  const content = await JSZip.loadAsync(arrayBuffer);
  for await (const [fileName, fileContent] of Object.entries(content.files)) {
    if ((fileContent as any).dir) continue;
    const fileData: string = await (fileContent as any).async("string");
    ret.push({ key: fileName, value: fileData });
  }
  return ret;
}

